impl FileBackedPageFault {
    pub fn load_page(&self) -> Result<Arc<Page>, PageFaultError> {
        let file_size = self
            .file
            .get_attr()
            .map_err(|_| PageFaultError::Invalid)?
            .st_size
            .max(0) as usize;
        if self.file_offset >= file_size {
            return Err(PageFaultError::Bus);
        }
        file_page_load(&self.file, self.pgoff).map_err(|_| PageFaultError::Invalid)
    }
}

fn resolve_existing_page_fault(
    page_table: &PageTable,
    area: &mut MapArea,
    vpn: VirtPageNum,
    access: PageFaultAccess,
    slot: PageSlot,
) -> Result<(), PageFaultError> {
    let vaddr: VirtAddr = vpn.into();
    // Write to a mapping without write permission → deliver SIGSEGV.
    if access == PageFaultAccess::Write && !area.map_perm.contains(MappingFlags::W) {
        return Err(PageFaultError::Invalid);
    }
    match slot {
        PageSlot::Frame(frame) => {
            if matches!(area.backend, MapBackend::SharedMemory { .. }) {
                // SysV SHM must remain physically shared across processes.
                // A write fault here should only restore the intended PTE flags,
                // never privatize the underlying frame.
                page_table.map_page(vaddr, frame.ppn.into(), area.map_perm, Page4KB);
            } else if Arc::strong_count(&frame) > 1 {
                let new_frame = frame_copy(&frame).ok_or(PageFaultError::Invalid)?;
                page_table.unmap_page(vaddr);
                page_table.map_page(vaddr, new_frame.ppn.into(), area.map_perm, Page4KB);
                area.data_frames.insert(vpn, PageSlot::Frame(new_frame));
            } else {
                page_table.map_page(vaddr, frame.ppn.into(), area.map_perm, Page4KB);
            }
        }
        PageSlot::FilePage(page) => {
            let MapBackend::FileBacked { shared, .. } = &area.backend else {
                return Err(PageFaultError::Invalid);
            };
            if *shared {
                let mut map_perm = area.map_perm;
                if area.map_perm.contains(MappingFlags::W) && access != PageFaultAccess::Write {
                    map_perm &= !MappingFlags::W;
                } else if access == PageFaultAccess::Write {
                    page.mark_dirty();
                }
                page_table.map_page(vaddr, PhysAddr::new(page.phys_addr()), map_perm, Page4KB);
            } else {
                let new_frame = frame_alloc().ok_or(PageFaultError::Invalid)?;
                page.copy_out(0, new_frame.ppn.get_bytes_array());
                page_table.unmap_page(vaddr);
                page_table.map_page(vaddr, new_frame.ppn.into(), area.map_perm, Page4KB);
                area.data_frames.insert(vpn, PageSlot::Frame(new_frame));
            }
        }
    }
    Ok(())
}

fn map_loaded_file_page(
    page_table: &PageTable,
    area: &mut MapArea,
    vpn: VirtPageNum,
    access: PageFaultAccess,
    shared: bool,
    page: Arc<Page>,
) {
    let vaddr: VirtAddr = vpn.into();
    let mut map_perm = area.map_perm;
    if !shared && area.map_perm.contains(MappingFlags::W) {
        map_perm &= !MappingFlags::W;
    } else if shared && area.map_perm.contains(MappingFlags::W) {
        if access == PageFaultAccess::Write {
            page.mark_dirty();
        } else {
            map_perm &= !MappingFlags::W;
        }
    }
    page_table.map_page(vaddr, PhysAddr::new(page.phys_addr()), map_perm, Page4KB);
    area.data_frames.insert(vpn, PageSlot::FilePage(page));
}

