/// Linear offset for kernel high-VA page table mappings.
///
/// Runtime symbol value = high VA.
/// offset = PPN - VPN = -(VIRT_ADDR_START >> 12), constant across all kernel sections.
const KERNEL_LINEAR_OFFSET: isize =
    -((polyhal::consts::VIRT_ADDR_START >> crate::config::PAGE_SIZE_BITS) as isize);

/// glibc RISC-V TLS Variant I (TLS_DTV_AT_TP): pthread_area 在 tp 之前，确保
/// `(struct pthread *)(tp - TLS_PRE_TCB_SIZE)` 和 `((tcbhead_t *)tp)[-1]` 落在已映射内存内。
/// glibc sizeof(struct pthread) ≈ 2320，对齐后取 0xA00 (2560B)。
const TLS_PRE_TCB_SIZE: usize = 0xA00;
/// RISC-V glibc tcbhead_t: dtv(8B) + private(8B) = 16B。
const TLS_TCB_SIZE: usize = 16;
/// dtv_t 数组。musl __copy_tls 期望 dtv[0].counter=6（generation），
/// 且循环体在 module count > 0 时会逐条目遍历 dtv。预留更多空间容纳模块条目。
/// 布局: [0]=generation, [1]=total_module_count, [2..]=per-module pointer。
const TLS_DTV_SIZE: usize = 128;

