// RAII: FrameTracker 释放时自动回收物理帧
pub struct FrameTracker {
    pub ppn: PhysPageNum,
}

impl FrameTracker {
    pub fn new(ppn: PhysPageNum) -> Self {
        let bytes_array = ppn.get_bytes_array();
        for i in bytes_array {
            *i = 0;
        }
        Self { ppn }
    }
}
impl Debug for FrameTracker {
    fn fmt(&self, f: &mut Formatter<'_>) -> fmt::Result {
        f.write_fmt(format_args!("FrameTracker:PPN={:#x}", self.ppn.0))
    }
}
impl Drop for FrameTracker {
    fn drop(&mut self) {
        frame_dealloc(self.ppn);
    }
}

trait FrameAllocator {
    fn new() -> Self;
    fn alloc(&mut self) -> Option<PhysPageNum>;
    fn alloc_more(&mut self, pages: usize) -> Option<Vec<PhysPageNum>>;
    fn dealloc(&mut self, ppn: PhysPageNum);
}

pub struct StackFrameAllocator {
    start: usize,
    current: usize,
    end: usize,
    recycled: Vec<usize>,
}

impl StackFrameAllocator {
    pub fn init(&mut self, l: PhysPageNum, r: PhysPageNum) {
        self.start = l.0;
        self.current = l.0;
        self.end = r.0;
    }
    /// 用于 sysinfo：返回 (total_frames, free_frames)
    pub fn stats(&self) -> (usize, usize) {
        let total = self.end - self.start;
        let free = self.end - self.current + self.recycled.len();
        (total, free)
    }
    #[allow(unused)]
    pub fn debug_current(&self) -> usize { self.current }
    #[allow(unused)]
    pub fn debug_end(&self) -> usize { self.end }
    #[allow(unused)]
    pub fn debug_recycled_len(&self) -> usize { self.recycled.len() }
}
impl FrameAllocator for StackFrameAllocator {
    fn new() -> Self {
        Self {
            start: 0,
            current: 0,
            end: 0,
            recycled: Vec::new(),
        }
    }
    fn alloc(&mut self) -> Option<PhysPageNum> {
        if let Some(ppn) = self.recycled.pop() {
            Some(PhysPageNum(ppn))
        } else if self.current == self.end {
            None
        } else {
            self.current += 1;
            Some(PhysPageNum(self.current - 1))
        }
    }
    fn alloc_more(&mut self, pages: usize) -> Option<Vec<PhysPageNum>> {
        // 单页分配（绝大多数 DMA bounce buffer）：优先用回收帧
        if pages == 1 {
            if let Some(ppn) = self.alloc() {
                let mut v = Vec::new();
                v.push(ppn);
                return Some(v);
            }
        }
        // 多页分配：优先从线性区分配（保证物理连续，DMA 需要）
        if self.current + pages < self.end {
            self.current += pages;
            let v: Vec<PhysPageNum> = (1..=pages).map(|x| PhysPageNum(self.current - x)).collect();
            return Some(v);
        }
        // 线性区不足时，尝试在 recycled 中寻找连续段
        alloc_contiguous_from_recycled(self, pages)
    }
    fn dealloc(&mut self, ppn: PhysPageNum) {
        let ppn = ppn.0;
        // validity check
        if ppn >= self.current || self.recycled.iter().any(|&v| v == ppn) {
            panic!("Frame ppn={:#x} has not been allocated!", ppn);
        }
        // recycle
        self.recycled.push(ppn);
    }
}

/// 在回收集中扫描连续物理页段。用于 DMA bounce buffer 等需要物理连续的场景。
fn alloc_contiguous_from_recycled(
    alloc: &mut StackFrameAllocator,
    pages: usize,
) -> Option<Vec<PhysPageNum>> {
    if pages == 0 {
        return Some(Vec::new());
    }
    let mut sorted: Vec<usize> = alloc.recycled.iter().copied().collect();
    sorted.sort_unstable();
    for window in sorted.windows(pages) {
        if window.last().unwrap() - window.first().unwrap() + 1 == pages {
            let result: Vec<PhysPageNum> = window
                .iter()
                .map(|&ppn| {
                    let pos = alloc.recycled.iter().position(|&x| x == ppn).unwrap();
                    alloc.recycled.remove(pos);
                    PhysPageNum(ppn)
                })
                .collect();
            return Some(result);
        }
    }
    None
}

