pub fn init_frame_allocator() {
    unsafe extern "C" {
        safe fn _end();
    }
    // _end 链接符号在 Sv39 高虚拟地址下运行时带 VIRT_ADDR_START 前缀，
    // 减去后得到物理地址（与 polyhal mem.rs 做法一致）
    let ekernel_pa = _end as usize - polyhal::consts::VIRT_ADDR_START;
    polyhal::println!("    FA init: _end={:#x} ekernel_pa={:#x}", _end as usize, ekernel_pa);
    FRAME_ALLOCATOR.exclusive_access().init(
        PhysAddr::new(ekernel_pa).ceil_pn(),
        PhysAddr::new(MEMORY_END).floor_pn(),
    );
