pub fn suspend_current_and_run_next() {
    // There must be an application running.
    let task = take_current_task().unwrap();
    // ---- access current TCB exclusively
    let mut task_inner = task.inner_exclusive_access();
    let kc_ptr = &mut task_inner.kcontext as *mut KContext;
    // Change status to Ready
    task_inner.task_status = TaskStatus::Ready;
    drop(task_inner);
    // ---- release current TCB

    // push back to ready queue.
    add_task(task);
    // jump to scheduling cycle
    schedule(kc_ptr);
}

/// This function must be followed by a schedule
pub fn block_current_task() -> *mut KContext {
    let task = take_current_task().unwrap();
    // Remove from ready queue so it won't be scheduled again until woken.
    TASK_MANAGER.exclusive_access().remove_task(&task);
    let mut task_inner = task.inner_exclusive_access();
    task_inner.task_status = TaskStatus::Blocked;
    note_task_blocked();
    &mut task_inner.kcontext as *mut KContext
}

pub fn set_current_block_reason(reason: &'static str) {
    if let Some(task) = current_task() {
        task.inner.exclusive_session(|inner| {
            inner.block_reason = Some(reason);
        });
    }
}

pub fn clear_current_block_reason() {
    if let Some(task) = current_task() {
        task.inner.exclusive_session(|inner| {
            inner.block_reason = None;
        });
    }
}

pub fn block_current_and_run_next() {
    let task_cx_ptr = block_current_task();
    schedule(task_cx_ptr);
}

/// Exit the current 'Running' task and run the next task in task list.
pub fn exit_current_and_run_next(exit_code: i32) {
    note_task_exit();
    let task = take_current_task().unwrap();
    let mut task_inner = task.inner_exclusive_access();
    let process = task.process.upgrade().unwrap();
    let tid = task_inner.res.as_ref().unwrap().tid;
    // record exit code（POSIX _exit: status & 0xff）
    task_inner.exit_code = Some(exit_code & 0xff);
    // set_tid_address(2): 线程退出时，若 clear_child_tid 非空，
    // 内核在对应地址写 0，配合 futex_wake 通知 musl 线程已终止。
    let clear_child_tid = task_inner.clear_child_tid;
    let clear_child_tid_ptid = task_inner.clear_child_tid_ptid;
    // set_robust_list(2): 线程退出时，若 robust_list_head 非空，
    // 内核遍历 robust futex 链表，对每个 futex 设 FUTEX_OWNER_DIED 并唤醒等待者。
    let robust_list_head = task_inner.robust_list_head;
    // 取出 TaskUserRes 但不立即 drop——drop 会释放用户栈物理页面。
    // 后续 clear_child_tid / ptid 扫描需要访问用户空间（ptid 常位于线程用户栈上），
    // 若提早释放 → 物理页被内核堆重用 → translated_refmut 经由残留页表写内核内存 → 堆损坏。
    let _saved_res = task_inner.res.take();
    // here we do not remove the thread since we are still using the kstack
    // it will be deallocated when sys_waittid is called
    drop(task_inner);
    // set_robust_list(2) exit cleanup: walk the robust futex list,
    // set FUTEX_OWNER_DIED on each futex word, and wake one waiter.
    // See Documentation/robust-futex-ABI.rst for the protocol.
    if robust_list_head != 0 {
        const FUTEX_OWNER_DIED: u32 = 0x40000000;
        const ROBUST_LIST_LIMIT: u32 = 2048;

        let process_inner = process.inner_exclusive_access();
        let pt = process_inner.memory_set.get_mut().page_table();

        // Read list.next (first field of robust_list_head at offset 0).
        let mut entry: usize = match translated_refmut(pt, robust_list_head as *mut usize) {
            Ok(v) => *v,
            Err(_) => 0,
        };

        // Empty check: if list.next == &list (i.e. == head), the list is empty.
        if entry != 0 && entry != robust_list_head {
            // Read futex_offset from offset 8 in robust_list_head.
            let futex_offset: isize = match translated_refmut(pt, (robust_list_head + 8) as *mut isize) {
                Ok(v) => *v,
                Err(_) => 0,
            };

            let mut count: u32 = 0;
            while entry != 0 && entry != robust_list_head && count < ROBUST_LIST_LIMIT {
                // futex word is at (void*)entry + futex_offset.
                let futex_addr = entry.wrapping_add(futex_offset as usize) as *mut u32;
                if let Ok(futex_word) = translated_refmut(pt, futex_addr) {
                    *futex_word |= FUTEX_OWNER_DIED;
                } else {
                    break; // bad pointer in list, stop walking
                }
                let _ = futex::futex_wake(futex_addr as usize, 1, 0);

                // Read next pointer from current robust_list entry.
                match translated_refmut(pt, entry as *mut usize) {
                    Ok(next_ptr) => entry = *next_ptr,
                    Err(_) => break,
                }
                count += 1;
            }
        }
        drop(process_inner);
    }
    if clear_child_tid != 0 {
        // 写 0 到用户空间 clear_child_tid 地址
        let process_inner = process.inner_exclusive_access();
        if let Ok(dst) =
            crate::mm::translated_refmut(process_inner.memory_set.get_mut().page_table(), clear_child_tid as *mut u32)
        {
            *dst = 0;
        }
        // Wake up any thread blocked in FUTEX_WAIT on clear_child_tid.
        // musl's pthread_join / __unlock relies on this to resume after a thread exits.
        futex::futex_wake(clear_child_tid, 1, 0);
