/// 每个时间片包含的 tick 数。当前 timer 中断频率 100 Hz（每 tick 10 ms），
/// 故 TIME_SLICE_TICKS=10 给出 100 ms 时间片，适合 LTP 批处理负载。
/// 每次任务切换（run_tasks 取出新任务）会将计数清零。
pub const TIME_SLICE_TICKS: usize = 10;

/// 全局 tick 计数器（UP 单核 + trap 时关中断，无需真原子操作）。
static TICK_COUNT: AtomicUsize = AtomicUsize::new(0);

/// 在任务切换时重置 tick 计数（由 run_tasks 调用）。
pub fn reset_tick_count() {
    TICK_COUNT.store(0, Ordering::Relaxed);
}

const TRAP_FROM_KERNEL: usize = 0;
const TRAP_FROM_USER: usize = 1;

/// KContext 的 KPC 入口：由 context_switch 首次进入，此后无限循环执行用户态。
pub fn user_loop() -> ! {
    loop {
        // 在每次进入用户态之前检查待处理信号，确保被其他线程
        // 通过 tkill(2) 发送的信号（如 SIGCANCEL）能被及时交付。
        handle_signals();
        let cx = current_trap_cx();
        run_user_task(cx); // sret → 用户态 → trap → kernel_callback → _interrupt_for_arch → 返回
    }
}

#[inline(always)]
fn trap_pc(ctx: &TrapFrame) -> usize {
    crate::arch::trap_pc(ctx)
}

fn panic_kernel_page_fault(addr: usize, ctx: &TrapFrame, what: &str) -> ! {
    if addr > VIRT_ADDR_START {
        if let Some(task) = crate::task::current_task() {
            let (bottom, _) = kernel_stack_position(task.kstack.0);
            let guard_bottom = bottom.saturating_sub(PAGE_SIZE);
            if addr >= guard_bottom && addr < bottom {
                panic!(
                    "kernel stack overflow in task tid={} pid={} at {:#x}",
                    task.inner_exclusive_access()
                        .res.as_ref()
                        .map(|r| r.tid)
                        .unwrap_or(0),
                    task.process.upgrade().map(|p| p.getpid()).unwrap_or(0),
                    addr,
                );
            }
        }
    }
    panic!("kernel {} at {:#x}, pc={:#x}", what, addr, trap_pc(ctx));
}

fn handle_user_trap(ctx: &mut TrapFrame, trap_type: TrapType) {
    if let Some(task) = crate::task::current_task() {
        task.inner_exclusive_access().time_stat.update_utime();
    }

    match trap_type {
        TrapType::SysCall => {
            ctx.syscall_ok();
            let result = syscall(
                ctx[TrapFrameArgs::SYSCALL],
                ctx.args(),
            );
            ctx[TrapFrameArgs::RET] = match result {
                Ok(v) => v,
                Err(e) => (-(e as isize)) as usize,
            };
            note_syscall_retired();
        }
        TrapType::Timer => {
            set_next_trigger();
            check_timer();
            on_timer_tick(crate::timer::get_time_ms());
            // 在挂起当前任务前检查信号
            handle_signals();
            // 时间片调度：累计 TIME_SLICE_TICKS 个 tick 后才让出 CPU
            let count = TICK_COUNT.fetch_add(1, Ordering::Relaxed) + 1;
            if count >= TIME_SLICE_TICKS {
                TICK_COUNT.store(0, Ordering::Relaxed);
                suspend_current_and_run_next();
            }
        }
        TrapType::SupervisorExternal => {
            crate::arch::board::irq_handler();
        }
        TrapType::BusError(_addr) => {
            let si = SigInfo::kernel_signal(SIGBUS as i32, BUS_ADRERR);
            add_signal_to_current(SIGBUS, si);
        }
        TrapType::StorePageFault(addr)
        | TrapType::LoadPageFault(addr)
        | TrapType::InstructionPageFault(addr) => {
            let access = match trap_type {
                TrapType::StorePageFault(_) => PageFaultAccess::Write,
                TrapType::LoadPageFault(_) => PageFaultAccess::Read,
                TrapType::InstructionPageFault(_) => PageFaultAccess::Execute,
                _ => unreachable!(),
            };
            let process = current_process();
            if let Some(mut inner) = process.try_inner_exclusive_access() {
                let prepared = inner
                    .memory_set
                    .get_mut()
                    .prepare_page_fault(VirtAddr::new(addr), access);
                drop(inner);
                match prepared {
                    Ok(PreparedPageFault::Resolved) => return,
                    Ok(PreparedPageFault::FileBacked(plan)) => {
                        match plan.load_page() {
                            Ok(page) => {
                                if let Some(mut inner) = process.try_inner_exclusive_access() {
                                    match inner
                                        .memory_set
                                        .get_mut()
                                        .commit_file_backed_page_fault(&plan, access, page)
                                    {
                                        Ok(()) => return,
                                        Err(crate::mm::PageFaultError::Bus) => {
                                            drop(inner);
                                            let si = SigInfo::kernel_signal(SIGBUS as i32, BUS_ADRERR);
                                            add_signal_to_current(SIGBUS, si);
                                            handle_signals();
                                            return;
                                        }
                                        Err(crate::mm::PageFaultError::Invalid) => {}
                                    }
                                    drop(inner);
                                }
                            }
                            Err(crate::mm::PageFaultError::Bus) => {
                                let si = SigInfo::kernel_signal(SIGBUS as i32, BUS_ADRERR);
                                add_signal_to_current(SIGBUS, si);
                                handle_signals();
                                return;
                            }
                            Err(crate::mm::PageFaultError::Invalid) => {}
                        }
                    }
                    Err(crate::mm::PageFaultError::Bus) => {
                        let si = SigInfo::kernel_signal(SIGBUS as i32, BUS_ADRERR);
                        add_signal_to_current(SIGBUS, si);
                        handle_signals();
                        return;
                    }
                    Err(crate::mm::PageFaultError::Invalid) => {}
