}

impl Dentry {
    fn register_live_dentry(dentry: &Arc<Self>) {
        LIVE_DENTRIES.exclusive_access().push(Arc::downgrade(dentry));
    }

    /// 创建新 dentry。若有 `inode` 则状态为 `Valid`，否则为 `Invalid`（negative dentry）。
    pub fn new(
        name: String,
        parent: Weak<Dentry>,
        inode: Option<Arc<Inode>>,
    ) -> Arc<Self> {
        let state = if inode.is_some() {
            DentryState::Valid
        } else {
            DentryState::Invalid
        };
        let dentry = Arc::new(Self {
            name,
            parent,
            inner: unsafe { UPSafeCellRaw::new(DentryInner { inode, state }) },
        });
        Self::register_live_dentry(&dentry);
        dentry
    }

    pub fn new_root(inode: Arc<Inode>) -> Arc<Self> {
        let dentry = Arc::new(Self {
            name: String::from("/"),
            parent: Weak::new(),
            inner: unsafe { UPSafeCellRaw::new(DentryInner {
                inode: Some(inode),
                state: DentryState::Valid,
            }) },
        });
        Self::register_live_dentry(&dentry);
        dentry
    }

    // ========== 状态管理 ==========

    fn get_state(&self) -> DentryState {
        self.inner.get_mut().state
    }

    fn set_state(&self, state: DentryState) {
        self.inner.get_mut().state = state;
    }

    pub fn inode(&self) -> Option<Arc<Inode>> {
        self.inner.get_mut().inode.clone()
    }

    fn is_negative_dentry(&self) -> bool {
        self.inner.get_mut().inode.is_none()
    }

    fn bind_inode(self: &Arc<Self>, inode: Arc<Inode>) {
        let inner = self.inner.get_mut();
        inner.inode = Some(inode);
        inner.state = DentryState::Valid;
    }

    fn reset_to_negative(&self) {
        let inner = self.inner.get_mut();
        inner.inode = None;
        inner.state = DentryState::Invalid;
    }

    fn matches_parent_name(self: &Arc<Self>, parent: &Arc<Dentry>, name: &str) -> bool {
        if self.name != name {
            return false;
        }
        self.parent
            .upgrade()
            .map(|p| Arc::ptr_eq(&p, parent))
            .unwrap_or(false)
    }

    fn relocate_in_place(self: &Arc<Self>, new_name: &str, new_parent: &Arc<Dentry>) {
        // SAFETY: Dentry 的命名关系只在 rename/mount 等命名空间写路径中更新；
        // 当前内核采用 UP 设计，调用方保证该更新发生在受控的 VFS 修改路径。
        unsafe {
            let name_ptr = core::ptr::addr_of!(self.name) as *mut String;
            let parent_ptr = core::ptr::addr_of!(self.parent) as *mut Weak<Dentry>;
            core::ptr::replace(name_ptr, String::from(new_name));
            core::ptr::replace(parent_ptr, Arc::downgrade(new_parent));
        }
    }

    pub fn relocate_live_dentries(
        old_parent: &Arc<Dentry>,
        old_name: &str,
        new_parent: &Arc<Dentry>,
        new_name: &str,
    ) -> Vec<Arc<Dentry>> {
        let mut registry = LIVE_DENTRIES.exclusive_access();
        let mut relocated = Vec::new();
        registry.retain(|weak| {
            let Some(dentry) = weak.upgrade() else {
                return false;
            };
            if dentry.matches_parent_name(old_parent, old_name) {
                dentry.relocate_in_place(new_name, new_parent);
                relocated.push(dentry);
            }
            true
        });
        relocated
    }

    // ========== 子树遍历 ==========

    /// 从全局 dcache 中按名称查找子节点。
    pub fn lookup_cached_child(self: &Arc<Self>, name: &str) -> Option<Arc<Dentry>> {
        dcache_lookup(self, name)
    }

    /// 从当前节点沿路径向下遍历，返回目标 Dentry。
    ///
