    pub ino: u64,
    pub fs_id: usize,
    state: UPIntrFreeCell<InodeMetaState>,
}

lazy_static! {
    static ref INODE_META_CACHE: UPIntrFreeCell<BTreeMap<(usize, u64), Weak<InodeMeta>>> = unsafe {
        UPIntrFreeCell::with_name(BTreeMap::new(), "INODE_META_CACHE")
    };
}

pub fn shared_inode_meta(fs_id: usize, ino: u64) -> Arc<InodeMeta> {
    if fs_id == 0 || ino == 0 {
        return Arc::new(InodeMeta::new(ino, fs_id));
    }
    let mut cache = INODE_META_CACHE.exclusive_access();
    if let Some(existing) = cache.get(&(fs_id, ino)).and_then(Weak::upgrade) {
        return existing;
    }
    cache.retain(|_, weak| weak.strong_count() > 0);
    let meta = Arc::new(InodeMeta::new(ino, fs_id));
    cache.insert((fs_id, ino), Arc::downgrade(&meta));
    meta
}

pub fn remove_inode_meta(fs_id: usize, ino: u64) {
    if fs_id == 0 || ino == 0 {
        return;
    }
    if let Some(meta) = INODE_META_CACHE
        .exclusive_access()
        .remove(&(fs_id, ino))
        .and_then(|weak| Weak::upgrade(&weak))
    {
        meta.invalidate();
    }
}

