        let state = self.state.exclusive_access();
        state.mode_valid.then_some(state.inner.mode)
    }

    pub fn size_if_valid(&self) -> Option<usize> {
        let state = self.state.exclusive_access();
        state.size_valid.then_some(state.inner.size)
    }

    pub fn attr_if_valid(&self) -> Option<InodeMetaInner> {
        let state = self.state.exclusive_access();
        state.attr_valid.then_some(state.inner)
    }

    pub fn apply_snapshot(&self, snapshot: InodeMetaInner) {
        let mut state = self.state.exclusive_access();
        state.inner = snapshot;
        state.mode_valid = true;
        state.size_valid = true;
        state.attr_valid = true;
    }

    pub fn invalidate(&self) {
        let mut state = self.state.exclusive_access();
        state.mode_valid = false;
        state.size_valid = false;
        state.attr_valid = false;
    }

    pub fn update_mode(&self, mode: InodeMode) {
        let mut state = self.state.exclusive_access();
        state.inner.mode = mode;
        state.mode_valid = true;
        state.attr_valid = false;
    }

    pub fn update_size(&self, size: usize) {
        let mut state = self.state.exclusive_access();
        state.inner.size = size;
        state.size_valid = true;
        state.attr_valid = false;
    }

