        let mut state = self.state.exclusive_access();
        state.inner.mode = InodeMode::from_bits_truncate(attr.st_mode);
        state.inner.size = attr.st_size.max(0) as usize;
        state.inner.nlink = attr.st_nlink;
        state.inner.uid = attr.st_uid;
        state.inner.gid = attr.st_gid;
        state.inner.rdev = attr.st_rdev;
        state.inner.blocks = attr.st_blocks;
        state.inner.atime = attr.st_atime;
        state.inner.mtime = attr.st_mtime;
        state.inner.ctime = attr.st_ctime;
        state.mode_valid = true;
        state.size_valid = true;
        state.attr_valid = true;
    }
}

