/// 实现 lose-net-stack 要求的网络发送接口。
#[derive(Debug)]
pub struct NetMod;

// ── Loopback 支持 ──

/// 本机 MAC 地址。
const LOCAL_MAC: [u8; 6] = [0x52, 0x54, 0x00, 0x12, 0x34, 0x56];

/// Ethernet 帧最小长度（不含 FCS）。
const ETH_HDR_LEN: usize = 14;

/// EtherType 常量。
const ETHERTYPE_ARP: u16 = 0x0806;
const ETHERTYPE_IPV4: u16 = 0x0800;

/// 检测 IPv4 地址是否为 loopback (127.0.0.0/8)。
fn is_loopback_ip(b: &[u8]) -> bool {
    b.len() >= 4 && b[0] == 127
}

/// 从以太帧 payload 中提取 IPv4 目标地址（大端序 4 字节）。
/// 返回 `None` 表示帧太短或不是标准 IPv4。
fn ipv4_dst_from_frame(data: &[u8]) -> Option<&[u8]> {
    if data.len() < ETH_HDR_LEN + 20 {
        return None;
    }
    // EtherType 在 offset 12..14
    let etype = u16::from_be_bytes([data[12], data[13]]);
    if etype != ETHERTYPE_IPV4 {
        return None;
    }
    // IPv4 头部 offset 14..34，目标 IP 在 offset 30..34
    Some(&data[30..34])
}

/// 从以太帧 payload 中提取 ARP 操作码和目标 IP。
/// 返回 `(operation, target_ip)`，`None` 表示不是 ARP 或帧太短。
fn arp_info_from_frame(data: &[u8]) -> Option<(u16, &[u8])> {
    if data.len() < ETH_HDR_LEN + 28 {
        return None;
    }
    let etype = u16::from_be_bytes([data[12], data[13]]);
    if etype != ETHERTYPE_ARP {
        return None;
    }
    let op = u16::from_be_bytes([data[20], data[21]]);
    // ARP 目标 IP 在 offset 38..42
    Some((op, &data[38..42]))
}

/// 构建 ARP 应答帧，把 `sender_mac`/`sender_ip` 作为应答的目标。
/// `reply_mac` 是我们要宣称的目标 MAC（即 127.0.0.1 对应的 MAC）。
fn build_arp_reply(request: &[u8], reply_mac: &[u8; 6]) -> [u8; 42] {
    let mut reply = [0u8; 42];
    // Ethernet header: dst = request src, src = reply_mac
    reply[0..6].copy_from_slice(&request[6..12]);  // dst = sender's MAC
    reply[6..12].copy_from_slice(reply_mac);        // src = our MAC
    reply[12..14].copy_from_slice(&[0x08, 0x06]);   // ARP
    // ARP payload
    reply[14..16].copy_from_slice(&[0x00, 0x01]);   // HW type: Ethernet
    reply[16..18].copy_from_slice(&[0x08, 0x00]);   // Proto: IPv4
    reply[18] = 6;                                   // HW addr len
    reply[19] = 4;                                   // Proto addr len
    reply[20..22].copy_from_slice(&[0x00, 0x02]);   // Operation: reply
    // Sender MAC = reply_mac, Sender IP = target IP from request
    reply[22..28].copy_from_slice(reply_mac);
    reply[28..32].copy_from_slice(&request[38..42]); // target IP → our IP in reply
    // Target MAC = sender MAC from request, Target IP = sender IP from request
    reply[32..38].copy_from_slice(&request[22..28]); // sender MAC → target MAC
    reply[38..42].copy_from_slice(&request[28..32]); // sender IP → target IP
    reply
}

impl NetInterface for NetMod {
    fn send(data: &[u8]) {
        // ── Loopback 检测 ──
        // 注意：lose-net-stack 的 TCP/UDP 层已内置 loopback 短路径
        // （TcpConnection::send_data / connect / UdpServer::sendto），
        // 对 127.0.0.1 的流量不会走到这里。此处处理漏网的 ARP 和 IP 包。

        // ARP: 仅拦截对 127.x.x.x 的请求（op=1）。应答（op=2）放行。
        if let Some((op, target_ip)) = arp_info_from_frame(data) {
            if op == 1 && is_loopback_ip(target_ip) {
                let reply = build_arp_reply(data, &LOCAL_MAC);
                NET_SERVER.analysis_net_data(&reply);
                return;
            }
            // ARP reply for loopback: 上游 analysis_arp() 对非本机 IP 的 ARP
            // 请求也会用 self.local_ip 回复，丢弃此类错误应答避免混淆。
            if op == 2 && is_loopback_ip(target_ip) {
                return;
            }
        }

        // IPv4: 目标为 127.x.x.x → 环回
        if let Some(dst) = ipv4_dst_from_frame(data) {
            if is_loopback_ip(dst) {
                NET_SERVER.analysis_net_data(data);
                return;
            }
        }

        // 正常路径：交由硬件发送
        NET_DEVICE.transmit(data);
    }

    fn local_mac_address() -> MacAddress {
        MacAddress::new(LOCAL_MAC)
    }
}

