/// 网络中断处理：从网卡收包 → 交给 NetServer 解析分发。
///
/// 由 PLIC IRQ handler 调用（SupervisorExternal 中断）。
/// 使用静态缓冲区避免每次中断都 heap 分配。
pub fn net_interrupt_handler() {
    static mut RECV_BUF: [u8; 2048] = [0u8; 2048];
    // SAFETY: 单核 UP + 中断上下文互斥，不存在竞态
    let buf = unsafe { &mut RECV_BUF[..] };

    if !NET_DEVICE.handle_interrupt() {
        return;
    }

    while let Ok(len) = NET_DEVICE.receive(buf) {
        NET_SERVER.analysis_net_data(&buf[..len]);
    }
}

#[allow(unused)]
pub fn hexdump(data: &[u8]) {
    const PRELAND_WIDTH: usize = 70;
    println!("[kernel] {:-^1$}", " hexdump ", PRELAND_WIDTH);
    for offset in (0..data.len()).step_by(16) {
        print!("[kernel] ");
        for i in 0..16 {
            if offset + i < data.len() {
                print!("{:02x} ", data[offset + i]);
            } else {
                print!("{:02} ", "");
            }
        }

        print!("{:>6}", ' ');

        for i in 0..16 {
            if offset + i < data.len() {
                let c = data[offset + i];
                if c >= 0x20 && c <= 0x7e {
                    print!("{}", c as char);
                } else {
                    print!(".");
                }
            } else {
                print!("{:02} ", "");
            }
        }

        println!("");
    }
    println!("[kernel] {:-^1$}", " hexdump end ", PRELAND_WIDTH);
}

