/// 接收缓冲区大小：以太网 MTU 1500 + 头部，取 2048 足够。
const RX_BUF_LEN: usize = 2048;
/// 队列深度，与新版 virtio-drivers 的 const generic 匹配。
const NET_QUEUE_SIZE: usize = 32;

lazy_static! {
    pub static ref NET_DEVICE: Arc<dyn NetDevice> = Arc::new(VirtIONetWrapper::new());
}

#[derive(Debug)]
pub enum NetError {
    NoData,
}

pub trait NetDevice: Send + Sync + Any {
    fn transmit(&self, data: &[u8]);
    fn receive(&self, data: &mut [u8]) -> Result<usize, NetError>;
    fn handle_interrupt(&self) -> bool;
    fn irq_line(&self) -> Option<usize> {
        None
    }
}

pub struct VirtIONetWrapper {
    device: UPIntrFreeCell<VirtIONet<VirtioHal, NetTransport, NET_QUEUE_SIZE>>,
    #[cfg(target_arch = "loongarch64")]
    irq_line: Option<usize>,
}

// SAFETY: UP 单核环境，关中断互斥访问，实际 Send + Sync。
unsafe impl Send for VirtIONetWrapper {}
unsafe impl Sync for VirtIONetWrapper {}

impl NetDevice for VirtIONetWrapper {
    fn transmit(&self, data: &[u8]) {
        let tx_buf = TxBuffer::from(data);
        if let Err(e) = self.device.exclusive_access().send(tx_buf) {
            polyhal::println!("[virtio-net] send failed: {:?}", e);
        }
    }

    fn receive(&self, data: &mut [u8]) -> Result<usize, NetError> {
        let mut net = self.device.exclusive_access();
        let rx_buf = net.receive().map_err(|_| NetError::NoData)?;
        let packet = rx_buf.packet();
        let len = packet.len().min(data.len());
        data[..len].copy_from_slice(&packet[..len]);
        net.recycle_rx_buffer(rx_buf).map_err(|_| NetError::NoData)?;
        Ok(len)
    }

    fn handle_interrupt(&self) -> bool {
        self.device.exclusive_access().ack_interrupt()
    }

    fn irq_line(&self) -> Option<usize> {
        #[cfg(target_arch = "loongarch64")]
        {
            self.irq_line
        }
        #[cfg(not(target_arch = "loongarch64"))]
        {
            None
        }
    }
}

impl VirtIONetWrapper {
    pub fn new() -> Self {
        let device = new_net_device();
        let transport = device.transport;

        let virtio = VirtIONet::<VirtioHal, NetTransport, NET_QUEUE_SIZE>::new(transport, RX_BUF_LEN)
            .expect("can't create net device by virtio");
        VirtIONetWrapper {
            device: unsafe { UPIntrFreeCell::new(virtio) },
            #[cfg(target_arch = "loongarch64")]
            irq_line: device.irq_line,
        }
    }
}

pub fn init() {
    lazy_static::initialize(&NET_DEVICE);
}

