#[derive(Copy, Clone, Debug)]
pub struct BlockIrqProbe {
    pub acked: bool,
    pub peek_used: Option<u16>,
    pub keep_masked: bool,
}

// SAFETY: UP 单核环境，访问通过 UPIntrFreeCell 关中断互斥，Send + Sync 安全。
unsafe impl Send for VirtIOBlock {}
unsafe impl Sync for VirtIOBlock {}

impl VirtIOBlock {
    pub fn new() -> Self {
        let device = new_block_device();
        Self::from_device(device)
    }

    /// 创建第二个 block 设备（x1/disk.img），用于放置 libgcc_s.so.1 等辅助文件。
    /// 返回 None 表示没有第二个 block 设备（本地测试常见）。
    pub fn new_second() -> Option<Self> {
        new_second_block_device().map(Self::from_device)
    }

    fn from_device(device: crate::arch::virtio::BlockDeviceAccess) -> Self {
        let transport = device.transport;

        let virtio_blk = unsafe {
            UPIntrFreeCell::new(
                VirtIOBlk::<VirtioHal, BlockTransport>::new(transport)
                    .expect("failed to create VirtIOBlk"),
            )
        };
        let (capacity, queue_size) = {
            let blk = virtio_blk.exclusive_access();
            (blk.capacity(), blk.virt_queue_size())
        };
        // polyhal::println!(
        //     "[virtio_blk] capacity={} sectors queue_size={}",
        //     capacity,
        //     queue_size
        // );

        let mut condvars = BTreeMap::new();
        for i in 0..queue_size {
            condvars.insert(i, Condvar::new());
        }
        Self {
            virtio_blk,
            condvars,
            #[cfg(not(target_arch = "loongarch64"))]
            mmio_base: device.mmio_base,
            #[cfg(target_arch = "loongarch64")]
            irq_line: device.irq_line,
        }
    }

    pub fn irq_line(&self) -> Option<usize> {
        #[cfg(target_arch = "loongarch64")]
        {
            self.irq_line
        }
        #[cfg(not(target_arch = "loongarch64"))]
        {
            None
        }
    }

    /// 返回该设备的 IRQ 号。
    #[cfg(not(target_arch = "loongarch64"))]
    pub fn plic_irq(&self) -> usize {
        const VIRTIO_MMIO_BASE: usize = 0x1000_1000;
        const VIRTIO_MMIO_STRIDE: usize = 0x1000;
        const VIRTIO_IRQ_BASE: usize = 1;
        VIRTIO_IRQ_BASE + (self.mmio_base.saturating_sub(VIRTIO_MMIO_BASE)) / VIRTIO_MMIO_STRIDE
    }
    #[cfg(target_arch = "loongarch64")]
    pub fn plic_irq(&self) -> usize {
        self.irq_line.unwrap_or(crate::arch::board::BLOCK_IRQ)
    }

    fn wake_used_token(&self, ack_interrupt: bool) -> BlockIrqProbe {
        self.virtio_blk.exclusive_session(|blk| {
            let acked = if ack_interrupt {
                // polyhal::println!("[virtio_blk] irq ack");
                blk.ack_interrupt()
            } else {
                false
            };
            let peek_used = blk.peek_used();
            if let Some(token) = peek_used {
                if let Some(condvar) = self.condvars.get(&token) {
                    // 新版 virtio-drivers 要等 owner 调 complete_* 才会真正 pop_used。
                    // 因此这里不能再像旧模型那样“IRQ 内完成全部回收”。
                    // IRQ 入口已先屏蔽 PLIC，这里只唤醒 waiter，保持屏蔽状态直到
                    // owner 完成 complete_* 后再决定是否链式推进或重开 IRQ。
                    // polyhal::println!(
                    //     "[virtio_blk] used token={} ready, wake waiter",
                    //     token
                    // );
                    condvar.signal();
                    let probe = BlockIrqProbe {
                        acked,
                        peek_used,
                        keep_masked: true,
                    };
                    return probe;
                }
                // polyhal::println!(
                //     "[virtio_blk] used token={} ready but condvar missing",
                //     token
                // );
            }
            // polyhal::println!("[virtio_blk] no used token pending");
            let probe = BlockIrqProbe {
                acked,
                peek_used,
                keep_masked: false,
            };
            probe
        })
    }

    fn complete_request_and_chain_wakeup(&self) {
        let probe = self.wake_used_token(false);
        if probe.keep_masked {
            // polyhal::println!("[virtio_blk] chain wake next completed request");
        } else {
            // polyhal::println!("[virtio_blk] no more completed requests, reenable irq");
            crate::arch::block::reenable_irq_for_with_reason(
                self.plic_irq(),
                "complete_chain:no_next_used",
            );
        }
    }

    /// IRQ 处理：确认中断，唤醒第一个已完成 token 的等待者。
    ///
    /// 相比 rCore 旧版在中断里 `pop_used()`，新版 virtio-drivers 只能先
    /// `peek_used()`，等请求 owner 在 `complete_*` 时真正消费 used ring。
    /// 因此这里先唤醒一个 waiter，后续请求在前一个 waiter 完成后继续链式推进。
    /// 返回值表示是否应继续保持块设备 IRQ 屏蔽，等待 owner 调 complete_*。
    pub fn handle_irq(&self) -> bool {
        // polyhal::println!("[virtio_blk] handle_irq");
        self.handle_irq_probe().keep_masked
    }

    pub fn handle_irq_probe(&self) -> BlockIrqProbe {
        self.wake_used_token(true)
    }

    /// 清除 VirtIOBlock 的待处理中断（ISR 确认）。
    /// 用于设备初始化后，消除同步 I/O 期间产生的未处理中断。
    pub fn drain_interrupt(&self) {
        self.virtio_blk.exclusive_session(|blk| {
            blk.ack_interrupt();
        });
    }

    pub fn debug_irq_state(&self) -> u32 {
        block_interrupt_status()
    }
}

