            VfsError::AlreadyExists    => SyscallErrNo::EEXIST,
            VfsError::InvalidData      => SyscallErrNo::EIO,
            VfsError::NoSpace          => SyscallErrNo::ENOSPC,
            VfsError::PermissionDenied => SyscallErrNo::EACCES,
            VfsError::DeviceError      => SyscallErrNo::EIO,
            VfsError::Busy             => SyscallErrNo::EBUSY,
            VfsError::NotEmpty         => SyscallErrNo::ENOTEMPTY,
            VfsError::InvalidInput     => SyscallErrNo::EINVAL,
            VfsError::EndOfFile        => SyscallErrNo::EINVAL,
            VfsError::WouldBlock       => SyscallErrNo::EAGAIN,
            VfsError::IllegalSeek     => SyscallErrNo::ESPIPE,
            VfsError::BrokenPipe      => SyscallErrNo::EPIPE,
            VfsError::SymlinkLoop     => SyscallErrNo::ELOOP,
            VfsError::NoDevice        => SyscallErrNo::ENXIO,
        }
    }
}

pub fn make_pipe(flags: OpenFlags) -> (Arc<VfsFile>, Arc<VfsFile>) {
    let nonblock = flags.contains(OpenFlags::O_NONBLOCK);
    let (reader, writer) = crate::pipe::create_pipe(nonblock);
    let rd_flags = OpenFlags::O_RDONLY | (flags & OpenFlags::O_NONBLOCK);
    let wr_flags = OpenFlags::O_WRONLY | (flags & OpenFlags::O_NONBLOCK);
    let reader_file = Arc::new(VfsFile::new_dev_with_flags(Inode::from_arc_ops(reader), rd_flags));
    let writer_file = Arc::new(VfsFile::new_dev_with_flags(Inode::from_arc_ops(writer), wr_flags));
    (reader_file, writer_file)
}

pub fn make_eventfd(initval: u64, semaphore: bool, nonblock: bool) -> Arc<VfsFile> {
    let inode = crate::eventfd::create_eventfd(initval, semaphore, nonblock);
    let flags = OpenFlags::O_RDWR | if nonblock { OpenFlags::O_NONBLOCK } else { OpenFlags::empty() };
    Arc::new(VfsFile::new_dev_with_flags(Inode::from_arc_ops(inode), flags))
}

pub fn init() {
    register_filesystem(Arc::new(RamFileSystem));
    register_filesystem(Arc::new(DevFileSystem));
    register_filesystem(Arc::new(ProcFileSystem));
    register_filesystem(Arc::new(TmpFileSystem));
    register_filesystem(Arc::new(Ext4FileSystem));
    register_filesystem(Arc::new(VFatFileSystem));

    // Set up the fd-to-inode callback for loop devices
    filesystem::devfs::loop_dev::set_fd_to_inode_callback(|fd| {
        let process = crate::task::current_process();
        let inner = process.inner_exclusive_access();
        let file = inner.fd_table.get_mut().get(fd).ok_or(VfsError::NotFound)?;
        Ok(file.inode().clone())
    });

    // 评测环境会通过 QEMU 的第一个 virtio-blk（drive id=x0）挂载提供测例的 ext4 镜像。
    // 内核侧将该设备约定为 "/dev/vda"，并优先尝试把它挂载为根文件系统。
    // 若 ext4 挂载失败则回退到 ramfs，保证系统仍可启动用于调试。
    crate::drivers::block::register_block_device("/dev/vda", crate::drivers::block::BLOCK_DEVICE.clone());

    // 第二个 virtio-blk（drive id=x1 / disk.img）用于内核的辅助文件（如 libgcc_s.so.1）。
    // 该设备是可选的：本地 QEMU 测试时可能不存在，此时静默跳过。
    if let Some(vdb) = crate::drivers::block::VirtIOBlock::new_second() {
        let vdb = Arc::new(vdb);
        // MBR 扫描期间的同步 I/O 会在 vdb 的 PLIC 线上留下待处理中断。
        // 若不清理，IRQ 全局使能后未识别的中断将反复触发导致 hang。
        vdb.drain_interrupt();
        crate::drivers::block::VDB_DEVICE.call_once(|| vdb.clone());
        crate::drivers::block::register_block_device("/dev/vdb", vdb);
    } else {
        polyhal::println!("[fs] no second block device, skip vdb");
    }
    polyhal::println!("[fs] register_block_device done, about to mount ext4");

    if mount("ext4", "/dev/vda", "/", "").is_err() {
        polyhal::println!("[fs] ext4 mount failed, falling back to ramfs");
        mount("ramfs", "none", "/", "").expect("failed to mount root ramfs");
    }

    mount("devfs", "none", "/dev", "").expect("failed to mount devfs");
    mount("tmpfs", "none", "/dev/shm", "").expect("failed to mount /dev/shm tmpfs");
    filesystem::procfs::register_mem_stats(crate::mm::frame_allocator_stats);
    mount("procfs", "none", "/proc", "").expect("failed to mount procfs");
    mount("tmpfs", "none", "/tmp", "").expect("failed to mount tmpfs");

    // 启动阶段打印根目录内容，便于确认挂载树是否符合预期。
    list_root();
}

pub fn list_test_scripts(cwd: &Arc<Dentry>) -> VfsRet<Vec<String>> {
    // 评测要求 OS 启动后扫描 ext4 根目录并串行执行各 *_testcode.sh。
    // 该函数只负责目录枚举与名称过滤，实际执行（fork/exec/wait/输出协议）由上层负责。
    let inode = cwd.inode().ok_or(VfsError::NotDirectory)?;
    if !inode.get_mode()?.is_dir() {
        return Err(VfsError::NotDirectory);
    }
    let mut out = Vec::new();
    let mut index = 0;
    loop {
        match inode.read_dir(index)? {
            Some(entry) => {
                if entry.name.ends_with("_testcode.sh") {
                    out.push(entry.name);
                }
                index += 1;
            }
            None => break,
        }
    }
    Ok(out)
}

pub fn debug_dump_dentry_children(dir: &Arc<Dentry>) -> VfsRet<()> {
    let inode = dir.inode().ok_or(VfsError::NotDirectory)?;
    if !inode.get_mode()?.is_dir() {
        return Err(VfsError::NotDirectory);
    }

    let mut entries = Vec::new();
    let mut index = 0;
    while let Some(entry) = inode.read_dir(index)? {
        entries.push(entry);
        index += 1;
    }
    entries.sort_by(|lhs, rhs| lhs.name.cmp(&rhs.name));

    println!(
        "[fs] full dir dump dir='{}' entries={} cache_hits={} cache_misses={} cache_len={}/{}",
        dir.path(),
        entries.len(),
        dentry_cache_hits(),
        dentry_cache_misses(),
        dentry_cache_len(),
        dentry_cache_cap()
    );

    // if entries.is_empty() {
    //     println!("  <empty directory>");
    //     return Ok(());
    // }
    //
