fn list_root() {
    let root = match get_root_dentry() {
        Ok(root) => root,
        Err(_) => {
            println!("[fs] list_root skipped: root dentry not available");
            return;
        }
    };

    let inode = match root.inode() {
        Some(inode) => inode,
        None => {
            println!("[fs] list_root skipped: root inode not available");
            return;
        }
    };

    let root_dir = VfsFile::new(inode, Some(root), OpenFlags::O_RDONLY | OpenFlags::O_DIRECTORY);

    println!("[fs] root entries:");
    match root_dir.read_dir_entries() {
        Ok(entries) => {
            for entry in entries {
                println!("  {}", entry.name);
            }
        }
        Err(err) => {
            println!("[fs] list_root aborted: {:?}", err);
        }
    }
}

