pub const SIG_UNBLOCK: u32 = 1;
pub const SIG_SETMASK: u32 = 2;

pub fn sigset_add(set: &mut SigSet, signo: usize) {
    *set |= 1 << (signo - 1);
}

pub fn sigset_del(set: &mut SigSet, signo: usize) {
    *set &= !(1 << (signo - 1));
}

pub fn sigset_contains(set: SigSet, signo: usize) -> bool {
    (set >> (signo - 1)) & 1 != 0
}

