/// Fast userspace locking (futex(2)).
///
/// Implements FUTEX_WAIT / FUTEX_WAKE for single-core UP environment.
///
/// ## Race-free design
/// The key invariant: checking `*uaddr == val` and enqueuing the current task
/// happen under the same `FUTEX_QUEUES` lock. This prevents the lost-wakeup race
/// where another thread modifies the futex word and calls FUTEX_WAKE between
/// our check and our enqueue.
///
/// ## Nested locking
/// On UP, `UPIntrFreeCell` uses nested interrupt masking (`IntrMaskingInfo`),
/// so holding the global futex lock while calling `translated_refmut` (which
/// acquires the process inner lock) and `wakeup_task` (which acquires the task
/// inner lock) is safe.
use alloc::collections::{BTreeMap, VecDeque};
use alloc::sync::Arc;
use alloc::vec::Vec;
use lazy_static::lazy_static;

use crate::sync::UPIntrFreeCell;
use crate::task::{TaskControlBlock, block_current_task, current_process, current_task, schedule, wakeup_task};
use crate::utils::{SyscallErrNo, SyscallRet};

/// One futex address's wait queue. Drop on empty is automatic via BTreeMap remove.
pub struct FutexBucket {
    wait_queue: VecDeque<Arc<TaskControlBlock>>,
}

lazy_static! {
    /// Global futex wait queues, keyed by user-space uaddr (as usize).
    /// UPIntrFreeCell with nesting support makes nested locking safe.
    static ref FUTEX_QUEUES: UPIntrFreeCell<BTreeMap<usize, FutexBucket>> =
        // SAFETY: initialised at boot on the single core before any task runs.
        unsafe { UPIntrFreeCell::with_name(BTreeMap::new(), "FUTEX_QUEUES") };
}

/// FUTEX_WAIT — block the current task if `*uaddr == val`.
///
/// Returns:
/// - `Ok(0)` on successful wake-up by FUTEX_WAKE
/// - `Err(EAGAIN)` if `*uaddr != val` at call time
/// - `Err(EINTR)` if a signal is pending after wake-up
pub fn futex_wait(uaddr: *mut u32, val: u32, futex_op: u32) -> SyscallRet {
    // Lock the global futex map first, then read *uaddr.
    // Both happen under the same critical section → no lost wakeup.
    let mut queues = FUTEX_QUEUES.exclusive_access();

    let process = current_process();
    let inner = process.inner_exclusive_access();
    let current_val = match crate::mm::translated_refmut(inner.memory_set.get_mut().page_table(), uaddr) {
        Ok(src) => *src,
        Err(_) => {
            drop(inner);
            drop(queues);
            return Err(SyscallErrNo::EFAULT);
        }
    };
    drop(inner);

    if current_val != val {
        drop(queues);
        return Err(SyscallErrNo::EAGAIN);
    }

    // 在入队阻塞之前检查 pending 信号（POSIX: 阻塞系统调用应在 sleep 前检查信号）。
    // pthread_cancel 依赖此行为：cancel point wrapper 先 sigprocmask(SIG_UNBLOCK, SIGCANCEL)
    // 再调用 futex_wait，若此时 SIGCANCEL 已 pending，必须返回 EINTR 让信号投递。
    let has_signal = crate::task::has_pending_signals().is_some();
    if has_signal {
        drop(queues);
        return Err(SyscallErrNo::EINTR);
    }

    // Still holding queues lock — enqueue atomically with the check above.
    let bucket = queues.entry(uaddr as usize).or_insert_with(|| FutexBucket {
        wait_queue: VecDeque::new(),
    });
    let task = current_task().unwrap();
    bucket.wait_queue.push_back(Arc::clone(&task));
    drop(queues);

    // Block and yield the CPU. When we return from schedule(), another task
    // has called futex_wake on this uaddr (or we got a spurious wakeup).
    crate::task::set_current_block_reason("futex");
    let kc_ptr = block_current_task();
    schedule(kc_ptr);
    crate::task::clear_current_block_reason();

    // Check for pending signals — if one exists, return EINTR so userland
    // can deliver it instead of retrying the futex.
    if let Err(e) = crate::task::check_signal_for_eintr() {
        // Remove self from FUTEX_QUEUES. If we don't, the dangling Arc keeps
        // the TCB alive after the task exits, but the kernel stack and user
        // resources are already freed. Later futex operations traversing the
        // queue will access freed resources → heap corruption / panic.
        let mut queues = FUTEX_QUEUES.exclusive_access();
        if let Some(bucket) = queues.get_mut(&(uaddr as usize)) {
            bucket.wait_queue.retain(|t| !Arc::ptr_eq(t, &task));
            if bucket.wait_queue.is_empty() {
                queues.remove(&(uaddr as usize));
            }
        }
        drop(queues);
        return Err(e);
    }
    Ok(0)
}

/// FUTEX_WAKE — wake up to `max_wake` tasks waiting on `uaddr`.
///
/// Returns the number of tasks actually woken.
///
/// The caller (sys_futex) passes this value back to userland, which is
/// the standard futex convention (e.g. musl uses it to decide whether
/// to spin or yield).
pub fn futex_wake(uaddr: usize, max_wake: usize, futex_op: u32) -> SyscallRet {
    let mut queues = FUTEX_QUEUES.exclusive_access();
    let mut woken: usize = 0;
    // println!("[futex] WAKE  uaddr=0x{:x} max_wake={} op=0x{:x}", uaddr, max_wake, futex_op);

    if let Some(bucket) = queues.get_mut(&uaddr) {
        while woken < max_wake {
            let next = bucket.wait_queue.pop_front();
            match next {
                Some(task) => {
                    // Signal-delivery may have already woken this task via
                    // add_signal_to_task.  Check before calling wakeup_task
                    // to avoid a duplicate runqueue entry.  The dedup in
                    // TaskManager::add is the final safety net for the
                    // narrow race window.
                    let already_ready = task.inner.exclusive_session(|ti| {
                        ti.task_status != crate::task::TaskStatus::Blocked
                    });
                    if already_ready {
                        continue;
                    }
                    wakeup_task(task);
                    woken += 1;
                }
                None => break,
            }
        }
        // Remove the bucket if it's now empty to avoid unbounded map growth.
        if bucket.wait_queue.is_empty() {
            queues.remove(&uaddr);
        }
    }

    drop(queues);
    // println!("[futex] WAKE  => woken={}", woken);
