//! Pipe (FIFO) implementation with Condvar-based wakeup.
//!
//! Linux pipe(2) semantics:
//! - Blocking read on empty pipe waits for writer to produce data
//! - Blocking write on full pipe waits for reader to consume data
//! - Read returns 0 (EOF) when all writers are gone and pipe is empty
//! - Write returns EPIPE (and raises SIGPIPE) when all readers are gone
//! - O_NONBLOCK returns EAGAIN immediately instead of blocking

use alloc::collections::VecDeque;
use alloc::sync::{Arc, Weak};

use filesystem::vfs_defs::{InodeMode, InodeOps, Kstat, PollEvents, VfsError, VfsRet};

use crate::sync::{Condvar, UPSafeCellRaw};
use crate::task::{current_task, has_pending_signals, schedule};

const PIPE_BUF_CAP: usize = 0x10000; // 64 KiB

// ── Shared queue + synchronization ──

struct PipeInner {
    queue: VecDeque<u8>,
    /// Writers wait here for readers to consume data (free up buffer space).
    read_wait: Condvar,
    /// Readers wait here for writers to produce data.
    write_wait: Condvar,
}

// ── PipeSender (write end) ──

pub struct PipeSender {
    inner: Arc<UPSafeCellRaw<PipeInner>>,
    /// Weak reference to detect reader liveness → EPIPE.
    receiver: Weak<PipeReceiver>,
    nonblock: bool,
}

/// When the last writer closes, wake blocked readers so they can detect EOF
/// (Weak::strong_count == 0) and return 0 instead of sleeping forever.
impl Drop for PipeSender {
    fn drop(&mut self) {
        self.inner.get_mut().write_wait.signal();
    }
}

impl InodeOps for PipeSender {
    fn write_at(&self, _offset: usize, buf: &[u8]) -> VfsRet<usize> {
        // POSIX: write to pipe with no readers → EPIPE
        if Weak::strong_count(&self.receiver) == 0 {
            return Err(VfsError::BrokenPipe);
        }
        // Writes <= PIPE_BUF must be atomic (all-or-nothing contiguous).
        // Writes >  PIPE_BUF may be non-atomic (split across multiple chunks).
        let atomic = buf.len() <= PIPE_BUF_CAP;
        let mut written = 0usize;

        loop {
            let mut inner = self.inner.get_mut();
            let available = PIPE_BUF_CAP.saturating_sub(inner.queue.len());
            let remaining = buf.len() - written;

            // Atomic writes need room for ALL remaining bytes at once;
            // non-atomic writes accept partial chunks.
            let can_write = if atomic {
                remaining <= available
            } else {
                available > 0
            };

            if can_write {
                let wlen = remaining.min(available);
                inner.queue.extend(buf[written..written + wlen].iter());
                written += wlen;
                // Wake blocked reader(s)
                self.inner.get_mut().write_wait.signal();

                if self.nonblock || written == buf.len() {
                    // Non-blocking: one chunk, may be partial for >PIPE_BUF writes.
                    // Blocking: all data written, done.
                    return Ok(written);
                }
                // Blocking mode with more data: continue to next chunk
                continue;
            }

            // Not enough space. Non-blocking → EAGAIN (or partial if any written).
            if self.nonblock {
                if written > 0 {
                    return Ok(written);
                }
                return Err(VfsError::WouldBlock);
            }

            // Blocking mode: enqueue and wait for reader to free space
            let task = self.inner.get_mut().read_wait.enqueue_current();
            // Recheck: reader may have died while we were enqueuing
            if Weak::strong_count(&self.receiver) == 0 {
                self.inner.get_mut().read_wait.dequeue(&task);
                if written > 0 {
                    return Ok(written);
                }
                return Err(VfsError::BrokenPipe);
            }
            // Recheck: reader may have freed space while we were enqueuing
            {
                let inner = self.inner.get_mut();
                let avail = PIPE_BUF_CAP.saturating_sub(inner.queue.len());
                let can_proceed = if atomic {
                    (buf.len() - written) <= avail
                } else {
                    avail > 0
                };
                if can_proceed {
                    inner.read_wait.dequeue(&task);
                    continue;
                }
            }
            // Block and switch away — woken by reader's read_wait.signal()
            // or by a signal arriving at this task (add_signal_to_task).
            let kc_ptr = self.inner.get_mut().read_wait.block_no_sched();
            schedule(kc_ptr.cast());
            // On wakeup, check for pending signals. If one exists,
            // dequeue from the wait_queue and propagate the error
            // so the syscall layer can deliver the signal.
            if has_pending_signals().is_some() {
                self.inner.get_mut().read_wait.dequeue(&task);
                if written > 0 {
                    return Ok(written);
                }
                return Err(VfsError::WouldBlock);
            }
        }
    }

    fn get_mode(&self) -> VfsRet<InodeMode> {
        Ok(InodeMode::S_IFIFO | InodeMode::S_IRUSR | InodeMode::S_IWUSR)
    }

    fn get_size(&self) -> VfsRet<usize> {
        Ok(self.inner.get_mut().queue.len())
    }

    fn get_attr(&self) -> VfsRet<Kstat> {
        Ok(Kstat {
            st_mode: (InodeMode::S_IFIFO | InodeMode::S_IRUSR | InodeMode::S_IWUSR).bits(),
            st_nlink: 1,
            st_blksize: 4096,
            ..Default::default()
        })
    }

    fn poll(&self, events: PollEvents) -> PollEvents {
        let mut result = PollEvents::empty();
        if Weak::strong_count(&self.receiver) == 0 {
            result |= PollEvents::POLLERR;
        } else if self.inner.get_mut().queue.len() < PIPE_BUF_CAP {
            result |= PollEvents::POLLOUT;
        }
        result & events
    }
}

