pub fn sys_exit(exit_code: i32) -> ! {
    let pid = current_task()
        .and_then(|t| t.process.upgrade().map(|p| p.getpid()))
        .unwrap_or(0);
    debug!("[sys_exit] pid={} exit_code={}", pid, exit_code);
    exit_current_and_run_next(exit_code);
    panic!("Unreachable in sys_exit!");
}

pub fn sys_yield() -> SyscallRet {
    suspend_current_and_run_next();
    Ok(0)
}

pub fn sys_getpid() -> SyscallRet {
    Ok(current_task().unwrap().process.upgrade().unwrap().getpid())
}

/// getppid(2) — 返回父进程 PID。
/// 若当前进程为 init (无父进程) 或父进程已退出且未被收养，返回 0。
pub fn sys_getppid() -> SyscallRet {
    let process = current_process();
    let inner = process.inner_exclusive_access();
    match &inner.parent {
        Some(weak) => match weak.upgrade() {
            Some(parent) => Ok(parent.getpid()),
            None => Ok(0),
        },
        None => Ok(0),
    }
}

/// clone(2) — 统一的进程/线程创建入口。
///
/// clone ABI 因架构而异：
///   a0 = flags (低8位=退出信号, 高56位=CloneFlags)
///   a1 = stack (子进程新栈指针，0 表示复用父栈)
///   a2 = parent_tid (CLONE_PARENT_SETTID 时写入)
///
/// RISC-V (CLONE_BACKWARDS):  a3 = tls,  a4 = ctid
/// LoongArch (standard):     a3 = ctid, a4 = tls
///
/// fork() 在 musl/glibc 中通过此入口实现：flags=SIGCHLD, stack=0。
pub fn sys_clone(
    flags: usize,
    stack: usize,
    parent_tid: *mut i32,
    a3: usize,
    a4: usize,
) -> SyscallRet {
    use crate::task::{CloneFlags, clone_exit_signal, clone_flags_from_raw, SIGCHLD};

    // 根据架构解释 a3/a4
    #[cfg(target_arch = "loongarch64")]
    let (tls, child_tid) = (a4, a3 as *mut i32);  // a3=ctid, a4=tls
    #[cfg(not(target_arch = "loongarch64"))]
    let (tls, child_tid) = (a3, a4 as *mut i32);   // RISC-V: a3=tls, a4=ctid

    let clone_flags = clone_flags_from_raw(flags);
    let exit_signal = clone_exit_signal(flags);

    let current_process = current_process();
    let new_pid_or_tid = current_process.clone_process(
        clone_flags,
        exit_signal,
        stack,
        parent_tid,
        tls,
        child_tid,
    )?;
    // clone_process 内部已设置子线程 RET=0
    Ok(new_pid_or_tid)
}

/// Shebang recursion limit (matches Linux BINPRM_MAX_RECURSION).
const MAX_SHEBANG_DEPTH: u32 = 5;

/// Parse `#!interpreter [optional_arg]` from the first line of file data.
/// Returns `(interpreter_path, optional_arg)` or `None` if not a script.
fn parse_shebang(data: &[u8]) -> Option<(String, String)> {
    if data.len() < 2 || data[0] != b'#' || data[1] != b'!' {
        return None;
    }
    // Extract first line up to newline, max 256 bytes after #!
    let end = data[2..]
        .iter()
        .position(|&b| b == b'\n')
        .map(|p| (p + 2).min(258))
        .unwrap_or(data.len().min(258));
    let line = core::str::from_utf8(&data[2..end]).ok()?;
    let line = line.trim_start_matches(|c: char| c == ' ' || c == '\t');
    if line.is_empty() {
        return None;
    }
    let mut parts = line.split_whitespace();
    let interp = String::from(parts.next()?);
    let opt_arg = String::from(parts.next().unwrap_or(""));
    Some((interp, opt_arg))
}

