/// 读取用户空间路径字符串，处理 file-backed 页的 lazy fault。
fn read_path_string(path: *const u8) -> Result<alloc::string::String, SyscallErrNo> {
    let process = current_process();
    {
        let inner = process.inner_exclusive_access();
        let pt = inner.memory_set.get_mut().page_table();
        if let Ok(s) = translated_str(pt, path) {
            return Ok(s);
        }
    }
    // 三阶段 fault
    let path_va = VirtAddr::new(path as usize);
    let prepared = {
        let inner = process.inner_exclusive_access();
        inner.memory_set.get_mut()
            .prepare_page_fault(path_va, PageFaultAccess::Read)
    };
    if let Ok(crate::mm::PreparedPageFault::FileBacked(plan)) = prepared {
        if let Ok(page) = plan.load_page() {
            if let Some(mut inner) = process.try_inner_exclusive_access() {
                let _ = inner.memory_set.get_mut()
                    .commit_file_backed_page_fault(&plan, PageFaultAccess::Read, page);
            }
        }
    }
    let inner = process.inner_exclusive_access();
    let pt = inner.memory_set.get_mut().page_table();
    translated_str(pt, path).map_err(|_| SyscallErrNo::EFAULT)
}
