fn write_value_to_user<T: Copy>(
    memory_set: &mut MemorySet,
    user_ptr: *mut u8,
    value: &T,
) -> SyscallRet {
    let len = core::mem::size_of::<T>();
    let buffers = translated_byte_buffer(memory_set, user_ptr as *const u8, len)?;
    let bytes = unsafe {
        core::slice::from_raw_parts((value as *const T).cast::<u8>(), len)
    };
    let mut copied = 0;
    for slice in buffers {
        let remain = len - copied;
        let copy_len = remain.min(slice.len());
        if copy_len == 0 {
            break;
        }
        slice[..copy_len].copy_from_slice(&bytes[copied..copied + copy_len]);
        copied += copy_len;
    }
    Ok(0)
}

