pub const IPC_PRIVATE: usize = 0;
pub const IPC_RMID: i32 = 0;
pub const IPC_STAT: i32 = 2;
pub const IPC_SET: i32 = 1;

bitflags! {
    /// SysV SHM 相关标志。
    ///
    /// 当前仅消费 `IPC_CREAT`/`IPC_EXCL` 以及 `SHM_RDONLY`/`SHM_EXEC`
    /// 这几个 `iozone` 会遇到的位，低 9 位权限位先保留但暂不做权限判定。
    pub struct KernIpcPerm: i32 {
        const SHM_R = 0o400;
        const SHM_W = 0o200;
        const IPC_CREAT = 0o1000;
        const IPC_EXCL = 0o2000;
        const SHM_RDONLY = 0o10000;
        const SHM_RND = 0o20000;
        const SHM_REMAP = 0o40000;
        const SHM_EXEC = 0o100000;
    }
}

#[derive(Clone)]
struct ShmSegment {
    key: Option<usize>,
    size: usize,
    frames: Vec<Arc<FrameTracker>>,
    /// 近似 Linux `IPC_RMID` 语义：
    /// 先从 key 空间摘除，不再允许通过 key 查找；
    /// 当最后一个进程 `shmdt()` 后再真正释放段对象。
    marked_for_removal: bool,
    attach_count: usize,
    pending_attach_count: usize,
}

pub struct ShmSegmentInfo {
    pub key: usize,
    pub size: usize,
    pub attach_count: usize,
}

struct ShmManager {
    next_id: usize,
    segments: BTreeMap<usize, ShmSegment>,
    keys: BTreeMap<usize, usize>,
}

impl ShmManager {
    const fn new() -> Self {
        Self {
            next_id: 1,
            segments: BTreeMap::new(),
            keys: BTreeMap::new(),
        }
    }

    fn alloc_frames(size: usize) -> Result<Vec<Arc<FrameTracker>>, SyscallErrNo> {
        if size == 0 {
            return Err(SyscallErrNo::EINVAL);
        }
        let pages = size.div_ceil(PAGE_SIZE);
        let mut frames = Vec::with_capacity(pages);
        for _ in 0..pages {
            let frame = super::frame_alloc().ok_or(SyscallErrNo::ENOMEM)?;
            frames.push(frame);
        }
        Ok(frames)
    }

    fn create_segment(&mut self, key: Option<usize>, size: usize) -> Result<usize, SyscallErrNo> {
        let id = self.next_id;
        self.next_id += 1;
        let segment = ShmSegment {
            key,
            size,
            frames: Self::alloc_frames(size)?,
            marked_for_removal: false,
            attach_count: 0,
            pending_attach_count: 0,
        };
        if let Some(key) = key {
            self.keys.insert(key, id);
        }
        self.segments.insert(id, segment);
        Ok(id)
    }

    fn shmget(
        &mut self,
        key: usize,
        size: usize,
        flags: KernIpcPerm,
    ) -> Result<usize, SyscallErrNo> {
        if key == IPC_PRIVATE {
            return self.create_segment(None, size);
        }
        if let Some(&shmid) = self.keys.get(&key) {
            let segment = self.segments.get(&shmid).ok_or(SyscallErrNo::EINVAL)?;
            if size > 0 && size > segment.size {
                return Err(SyscallErrNo::EINVAL);
            }
            if flags.contains(KernIpcPerm::IPC_CREAT | KernIpcPerm::IPC_EXCL) {
                return Err(SyscallErrNo::EEXIST);
            }
            return Ok(shmid);
        }
        if !flags.contains(KernIpcPerm::IPC_CREAT) {
            return Err(SyscallErrNo::ENOENT);
        }
        self.create_segment(Some(key), size)
    }

    fn begin_user_attach(&mut self, shmid: usize) -> Result<Vec<Arc<FrameTracker>>, SyscallErrNo> {
        let Some(segment) = self.segments.get_mut(&shmid) else {
            return Err(SyscallErrNo::EINVAL);
        };
        if segment.marked_for_removal {
            return Err(SyscallErrNo::EIDRM);
        }
        segment.pending_attach_count += 1;
        Ok(segment.frames.clone())
    }

    fn finish_user_attach(&mut self, shmid: usize) -> Result<(), SyscallErrNo> {
        let Some(segment) = self.segments.get_mut(&shmid) else {
            return Err(SyscallErrNo::EINVAL);
        };
        if segment.pending_attach_count == 0 {
            return Err(SyscallErrNo::EINVAL);
        }
        segment.pending_attach_count -= 1;
        segment.attach_count += 1;
        Ok(())
    }

    fn abort_user_attach(&mut self, shmid: usize) -> Result<(), SyscallErrNo> {
        let Some(segment) = self.segments.get_mut(&shmid) else {
            return Err(SyscallErrNo::EINVAL);
        };
        if segment.pending_attach_count == 0 {
            return Err(SyscallErrNo::EINVAL);
        }
        segment.pending_attach_count -= 1;
        let should_remove =
            segment.marked_for_removal && segment.attach_count == 0 && segment.pending_attach_count == 0;
        if should_remove {
            self.segments.remove(&shmid);
        }
        Ok(())
    }

    fn attach_inherited(&mut self, shmid: usize) -> Result<(), SyscallErrNo> {
        let Some(segment) = self.segments.get_mut(&shmid) else {
            return Err(SyscallErrNo::EINVAL);
        };
        segment.attach_count += 1;
        Ok(())
    }

    fn detach(&mut self, shmid: usize) -> Result<(), SyscallErrNo> {
        let Some(segment) = self.segments.get_mut(&shmid) else {
            return Err(SyscallErrNo::EINVAL);
        };
        if segment.attach_count == 0 {
            return Err(SyscallErrNo::EINVAL);
        }
        segment.attach_count -= 1;
        let should_remove =
            segment.marked_for_removal && segment.attach_count == 0 && segment.pending_attach_count == 0;
        if should_remove {
            self.segments.remove(&shmid);
        }
        Ok(())
    }

    fn remove_id(&mut self, shmid: usize) -> Result<(), SyscallErrNo> {
        let Some(segment) = self.segments.get_mut(&shmid) else {
            return Err(SyscallErrNo::EINVAL);
        };
        if let Some(key) = segment.key.take() {
            self.keys.remove(&key);
        }
        segment.marked_for_removal = true;
        if segment.attach_count == 0 && segment.pending_attach_count == 0 {
            self.segments.remove(&shmid);
        }
        Ok(())
    }

    fn stat(&self, shmid: usize) -> Result<ShmSegmentInfo, SyscallErrNo> {
        let segment = self.segments.get(&shmid).ok_or(SyscallErrNo::EINVAL)?;
        Ok(ShmSegmentInfo {
            key: segment.key.unwrap_or(IPC_PRIVATE),
            size: segment.size,
            attach_count: segment.attach_count,
        })
    }
}

