pub struct PLIC {
    base_addr: usize,
}

#[derive(Copy, Clone)]
pub enum IntrTargetPriority {
    Machine = 0,
    Supervisor = 1,
}

impl IntrTargetPriority {
    pub fn supported_number() -> usize {
        2
    }
}

impl PLIC {
    fn pending_ptr(&self, intr_source_id: usize) -> (*const u32, usize) {
        assert!(intr_source_id > 0 && intr_source_id <= 132);
        let (reg_id, reg_shift) = (intr_source_id / 32, intr_source_id % 32);
        (
            (self.base_addr + 0x1000 + 0x4 * reg_id) as *const u32,
            reg_shift,
        )
    }
    fn priority_ptr(&self, intr_source_id: usize) -> *mut u32 {
        assert!(intr_source_id > 0 && intr_source_id <= 132);
        (self.base_addr + intr_source_id * 4) as *mut u32
    }
    fn hart_id_with_priority(hart_id: usize, target_priority: IntrTargetPriority) -> usize {
        let priority_num = IntrTargetPriority::supported_number();
        hart_id * priority_num + target_priority as usize
    }
    fn enable_ptr(
        &self,
        hart_id: usize,
        target_priority: IntrTargetPriority,
        intr_source_id: usize,
    ) -> (*mut u32, usize) {
        let id = Self::hart_id_with_priority(hart_id, target_priority);
        let (reg_id, reg_shift) = (intr_source_id / 32, intr_source_id % 32);
        (
            (self.base_addr + 0x2000 + 0x80 * id + 0x4 * reg_id) as *mut u32,
            reg_shift,
        )
    }
    fn threshold_ptr_of_hart_with_priority(
        &self,
        hart_id: usize,
        target_priority: IntrTargetPriority,
    ) -> *mut u32 {
        let id = Self::hart_id_with_priority(hart_id, target_priority);
        (self.base_addr + 0x20_0000 + 0x1000 * id) as *mut u32
    }
    fn claim_comp_ptr_of_hart_with_priority(
        &self,
        hart_id: usize,
        target_priority: IntrTargetPriority,
    ) -> *mut u32 {
        let id = Self::hart_id_with_priority(hart_id, target_priority);
        (self.base_addr + 0x20_0004 + 0x1000 * id) as *mut u32
    }
    pub unsafe fn new(base_addr: usize) -> Self {
        Self { base_addr }
    }
    pub fn set_priority(&mut self, intr_source_id: usize, priority: u32) {
        assert!(priority < 8);
        unsafe {
            self.priority_ptr(intr_source_id).write_volatile(priority);
        }
    }
    #[allow(unused)]
    pub fn get_priority(&mut self, intr_source_id: usize) -> u32 {
        unsafe { self.priority_ptr(intr_source_id).read_volatile() & 7 }
    }
    pub fn enable(
        &mut self,
        hart_id: usize,
        target_priority: IntrTargetPriority,
        intr_source_id: usize,
    ) {
        let (reg_ptr, shift) = self.enable_ptr(hart_id, target_priority, intr_source_id);
        unsafe {
            reg_ptr.write_volatile(reg_ptr.read_volatile() | 1 << shift);
        }
    }
    pub fn is_enabled(
        &self,
        hart_id: usize,
        target_priority: IntrTargetPriority,
        intr_source_id: usize,
    ) -> bool {
        let (reg_ptr, shift) = self.enable_ptr(hart_id, target_priority, intr_source_id);
        unsafe { (reg_ptr.read_volatile() & (1u32 << shift)) != 0 }
    }
    #[allow(unused)]
    pub fn disable(
        &mut self,
        hart_id: usize,
        target_priority: IntrTargetPriority,
        intr_source_id: usize,
    ) {
        let (reg_ptr, shift) = self.enable_ptr(hart_id, target_priority, intr_source_id);
        unsafe {
            reg_ptr.write_volatile(reg_ptr.read_volatile() & (!(1u32 << shift)));
        }
    }
    pub fn is_pending(&self, intr_source_id: usize) -> bool {
        let (reg_ptr, shift) = self.pending_ptr(intr_source_id);
        unsafe { (reg_ptr.read_volatile() & (1u32 << shift)) != 0 }
    }
    pub fn set_threshold(
        &mut self,
        hart_id: usize,
        target_priority: IntrTargetPriority,
        threshold: u32,
    ) {
        assert!(threshold < 8);
        let threshold_ptr = self.threshold_ptr_of_hart_with_priority(hart_id, target_priority);
        unsafe {
            threshold_ptr.write_volatile(threshold);
        }
    }
    #[allow(unused)]
    pub fn get_threshold(&mut self, hart_id: usize, target_priority: IntrTargetPriority) -> u32 {
        let threshold_ptr = self.threshold_ptr_of_hart_with_priority(hart_id, target_priority);
        unsafe { threshold_ptr.read_volatile() & 7 }
    }
    pub fn claim(&mut self, hart_id: usize, target_priority: IntrTargetPriority) -> u32 {
        let claim_comp_ptr = self.claim_comp_ptr_of_hart_with_priority(hart_id, target_priority);
        unsafe { claim_comp_ptr.read_volatile() }
    }
    pub fn complete(
        &mut self,
        hart_id: usize,
        target_priority: IntrTargetPriority,
        completion: u32,
    ) {
        let claim_comp_ptr = self.claim_comp_ptr_of_hart_with_priority(hart_id, target_priority);
        unsafe {
            claim_comp_ptr.write_volatile(completion);
        }
    }
}

use alloc::collections::{BTreeMap, VecDeque};
use alloc::sync::Arc;
use alloc::vec::Vec;
use lazy_static::lazy_static;

use crate::mm::translated_ref;
use crate::sync::UPIntrFreeCell;
use crate::task::{
    TaskControlBlock, block_current_task, current_process, current_task, schedule, wakeup_task,
};
use crate::utils::{SyscallErrNo, SyscallRet};

const IPC_PRIVATE: usize = 0;
const IPC_CREAT: i32 = 0o1000;
const IPC_EXCL: i32 = 0o2000;
const IPC_NOWAIT: i16 = 0o4000;
const SEM_UNDO: i16 = 0x1000;

const IPC_RMID: i32 = 0;
const GETPID: i32 = 11;
const GETVAL: i32 = 12;
const GETNCNT: i32 = 14;
const GETZCNT: i32 = 15;
const SETVAL: i32 = 16;

const SEMMNI: usize = 128;
const SEMMSL: usize = 256;
const SEMOPM: usize = 32;
const SEMVMX: i32 = 32_767;

#[repr(C)]
#[derive(Clone, Copy, Debug)]
struct Sembuf {
    sem_num: u16,
    sem_op: i16,
    sem_flg: i16,
}

#[derive(Clone, Copy, Debug)]
enum WaitReason {
    Zero(u16),
    Increase(u16),
}

struct SemState {
    value: u16,
    last_pid: usize,
}

struct SemWaiter {
    task: Arc<TaskControlBlock>,
    ops: Vec<Sembuf>,
    reason: WaitReason,
}

struct SemSet {
    key: Option<usize>,
    sems: Vec<SemState>,
    waiters: VecDeque<SemWaiter>,
    removed: bool,
    mode: u16,
    otime: i64,
    ctime: i64,
}

struct SemManager {
    next_id: usize,
    sets: BTreeMap<usize, SemSet>,
    keys: BTreeMap<usize, usize>,
}

impl SemManager {
    const fn new() -> Self {
        Self {
            next_id: 1,
            sets: BTreeMap::new(),
            keys: BTreeMap::new(),
        }
    }

    fn now_secs() -> i64 {
        (crate::timer::get_time_ms() / 1000) as i64
    }

    fn maybe_remove_if_dead(&mut self, semid: usize) {
        let should_remove = self
            .sets
            .get(&semid)
            .map(|set| set.removed && set.waiters.is_empty())
            .unwrap_or(false);
        if should_remove {
            self.sets.remove(&semid);
        }
    }

    fn cleanup_waiter_for_task(&mut self, semid: usize, task: &Arc<TaskControlBlock>) {
        if let Some(set) = self.sets.get_mut(&semid) {
            set.waiters.retain(|waiter| !Arc::ptr_eq(&waiter.task, task));
        }
        self.maybe_remove_if_dead(semid);
    }

    fn wake_ready_waiters(&mut self, semid: usize) -> Vec<Arc<TaskControlBlock>> {
        let mut ready = Vec::new();
        let Some(set) = self.sets.get_mut(&semid) else {
            return ready;
        };

        if set.removed {
            while let Some(waiter) = set.waiters.pop_front() {
                ready.push(waiter.task);
            }
            return ready;
        }

        let mut kept = VecDeque::new();
        while let Some(waiter) = set.waiters.pop_front() {
            match check_semop_ready(set, &waiter.ops) {
                Ok(()) => ready.push(waiter.task),
                Err(CheckResult::Blocked(_)) => kept.push_back(waiter),
                Err(CheckResult::Err(_)) => ready.push(waiter.task),
            }
        }
        set.waiters = kept;
        ready
    }
}

lazy_static! {
    static ref SEM_MANAGER: UPIntrFreeCell<SemManager> =
        unsafe { UPIntrFreeCell::with_name(SemManager::new(), "SEM_MANAGER") };
}

enum CheckResult {
    Blocked(WaitReason),
    Err(SyscallErrNo),
}

fn read_sembuf_array(sops: *const u8, nsops: usize) -> Result<Vec<Sembuf>, SyscallErrNo> {
    if sops.is_null() {
        return Err(SyscallErrNo::EFAULT);
    }
    if nsops == 0 || nsops > SEMOPM {
        return Err(SyscallErrNo::E2BIG);
    }
    let process = current_process();
    let inner = process.inner_exclusive_access();
    let pt = inner.memory_set.get_mut().page_table();
    let mut ops = Vec::with_capacity(nsops);
    for i in 0..nsops {
        let ptr = unsafe { (sops as *const Sembuf).add(i) };
        ops.push(*translated_ref(pt, ptr)?);
    }
    Ok(ops)
}

fn check_semop_ready(set: &SemSet, ops: &[Sembuf]) -> Result<(), CheckResult> {
    let mut temp = set
        .sems
        .iter()
        .map(|sem| sem.value as i32)
        .collect::<Vec<_>>();

    for op in ops {
        let sem_num = op.sem_num as usize;
        if sem_num >= temp.len() {
            return Err(CheckResult::Err(SyscallErrNo::EFBIG));
        }
        let valid_flags = IPC_NOWAIT | SEM_UNDO;
        if op.sem_flg & !valid_flags != 0 {
            return Err(CheckResult::Err(SyscallErrNo::EINVAL));
        }
        if op.sem_flg & SEM_UNDO != 0 {
            return Err(CheckResult::Err(SyscallErrNo::ENOSYS));
        }
        if op.sem_op > 0 {
            let next = temp[sem_num] + op.sem_op as i32;
            if next > SEMVMX {
                return Err(CheckResult::Err(SyscallErrNo::ERANGE));
            }
            temp[sem_num] = next;
            continue;
        }
        if op.sem_op == 0 {
            if temp[sem_num] == 0 {
                continue;
            }
            if op.sem_flg & IPC_NOWAIT != 0 {
                return Err(CheckResult::Err(SyscallErrNo::EAGAIN));
            }
            return Err(CheckResult::Blocked(WaitReason::Zero(op.sem_num)));
        }

        let need = -(op.sem_op as i32);
        if temp[sem_num] >= need {
            temp[sem_num] -= need;
            continue;
        }
        if op.sem_flg & IPC_NOWAIT != 0 {
            return Err(CheckResult::Err(SyscallErrNo::EAGAIN));
        }
        return Err(CheckResult::Blocked(WaitReason::Increase(op.sem_num)));
    }
    Ok(())
}

fn apply_semop(set: &mut SemSet, ops: &[Sembuf], pid: usize) {
    for op in ops {
        let sem = &mut set.sems[op.sem_num as usize];
        if op.sem_op > 0 {
            sem.value = (sem.value as i32 + op.sem_op as i32) as u16;
        } else if op.sem_op < 0 {
            sem.value = (sem.value as i32 + op.sem_op as i32) as u16;
        }
        sem.last_pid = pid;
    }
    set.otime = SemManager::now_secs();
}

fn count_waiters(set: &SemSet, semnum: usize, zero_wait: bool) -> usize {
    set.waiters
        .iter()
        .filter(|waiter| match waiter.reason {
            WaitReason::Zero(num) => zero_wait && num as usize == semnum,
            WaitReason::Increase(num) => !zero_wait && num as usize == semnum,
        })
        .count()
}

pub fn sys_semget(key: usize, nsems: usize, semflg: i32) -> SyscallRet {
    if nsems > SEMMSL {
        return Err(SyscallErrNo::EINVAL);
    }

    let mut manager = SEM_MANAGER.exclusive_access();
    if key != IPC_PRIVATE {
        if let Some(&semid) = manager.keys.get(&key) {
            let set = manager.sets.get(&semid).ok_or(SyscallErrNo::EINVAL)?;
            if set.removed {
                return Err(SyscallErrNo::EIDRM);
            }
            if (semflg & (IPC_CREAT | IPC_EXCL)) == (IPC_CREAT | IPC_EXCL) {
                return Err(SyscallErrNo::EEXIST);
            }
            if nsems != 0 && nsems > set.sems.len() {
                return Err(SyscallErrNo::EINVAL);
            }
