#[cfg(feature = "lock_debug")]
use core::sync::atomic::{AtomicUsize, Ordering};

pub trait Mutex: Sync + Send {
    fn lock(&self);
    fn unlock(&self);
}

pub struct MutexSpin {
    locked: UPIntrFreeCell<bool>,
    #[cfg(feature = "lock_debug")]
    name: &'static str,
    #[cfg(feature = "lock_debug")]
    holder_pc: AtomicUsize,
    #[cfg(feature = "lock_debug")]
    holder_loc: AtomicUsize,
}

#[cfg(feature = "lock_debug")]
macro_rules! caller_pc {
    () => {{
        let pc: usize;
        #[cfg(target_arch = "riscv64")]
        unsafe { core::arch::asm!("mv {}, ra", out(reg) pc) };
        #[cfg(target_arch = "loongarch64")]
        unsafe { core::arch::asm!("move {}, $r1", out(reg) pc) };
        pc
    }};
}

impl MutexSpin {
    pub fn new() -> Self {
        Self {
            locked: unsafe { UPIntrFreeCell::new(false) },
            #[cfg(feature = "lock_debug")]
            name: "",
            #[cfg(feature = "lock_debug")]
            holder_pc: AtomicUsize::new(0),
            #[cfg(feature = "lock_debug")]
            holder_loc: AtomicUsize::new(0),
        }
    }

    #[cfg(feature = "lock_debug")]
    pub unsafe fn with_name(name: &'static str) -> Self {
        Self {
            locked: unsafe { UPIntrFreeCell::new(false) },
            name,
            holder_pc: AtomicUsize::new(0),
            holder_loc: AtomicUsize::new(0),
        }
    }

    #[cfg(not(feature = "lock_debug"))]
    pub unsafe fn with_name(_name: &'static str) -> Self {
        Self::new()
    }
}

impl Mutex for MutexSpin {
    #[track_caller]
    fn lock(&self) {
        #[cfg(feature = "lock_debug")]
        let loc = core::panic::Location::caller();
        #[cfg(feature = "lock_debug")]
        let pc = caller_pc!();
        #[cfg(feature = "lock_debug")]
        let mut spins: usize = 0;

        loop {
            let mut locked = self.locked.exclusive_access();
            if *locked {
                drop(locked);
                #[cfg(feature = "lock_debug")]
                {
                    spins += 1;
                    if spins == 1000 {
                        let holder = self.holder_pc.load(Ordering::Acquire);
                        let holder_loc = self.holder_loc.load(Ordering::Acquire);
                        let holder_loc = if holder_loc == 0 {
                            None
                        } else {
                            Some(unsafe {
                                &*(holder_loc as *const core::panic::Location<'static>)
                            })
                        };
                        panic!(
                            "MutexSpin DEADLOCK: '{}' held at {}:{} (PC {:#x}), waiter spun {} times at {}:{} (PC {:#x})",
                            self.name,
                            holder_loc.map(|l| l.file()).unwrap_or("<unknown>"),
                            holder_loc.map(|l| l.line()).unwrap_or(0),
                            holder,
                            spins,
                            loc.file(),
                            loc.line(),
                            pc
                        );
                    }
                }
                (task_ops().suspend_current_and_run_next)();
                continue;
            } else {
                *locked = true;
                #[cfg(feature = "lock_debug")]
                {
                    self.holder_pc.store(pc, Ordering::Release);
                    self.holder_loc
                        .store(loc as *const _ as usize, Ordering::Release);
                }
                return;
            }
        }
    }

    fn unlock(&self) {
        #[cfg(feature = "lock_debug")]
        {
            self.holder_pc.store(0, Ordering::Release);
            self.holder_loc.store(0, Ordering::Release);
        }
        let mut locked = self.locked.exclusive_access();
        *locked = false;
    }
}

pub struct MutexBlocking {
    inner: UPIntrFreeCell<MutexBlockingInner>,
}

pub struct MutexBlockingInner {
    locked: bool,
    wait_queue: VecDeque<TaskHandle>,
}

impl MutexBlocking {
    pub fn new() -> Self {
        Self {
            inner: unsafe {
                UPIntrFreeCell::new(MutexBlockingInner {
                    locked: false,
                    wait_queue: VecDeque::new(),
                })
            },
        }
    }
}

impl Mutex for MutexBlocking {
    fn lock(&self) {
        let mut mutex_inner = self.inner.exclusive_access();
        if mutex_inner.locked {
            mutex_inner.wait_queue.push_back(TaskHandle::current());
            drop(mutex_inner);
            (task_ops().set_current_block_reason)("mutex");
            (task_ops().block_current_and_run_next)();
            (task_ops().clear_current_block_reason)();
        } else {
            mutex_inner.locked = true;
        }
    }

    fn unlock(&self) {
        let mut mutex_inner = self.inner.exclusive_access();
        assert!(mutex_inner.locked);
        if let Some(waking_task) = mutex_inner.wait_queue.pop_front() {
            (task_ops().wakeup_task)(waking_task.into_raw());
        } else {
            mutex_inner.locked = false;
        }
    }
}

