pub fn device_init() {
    let mut plic = unsafe { PLIC::new(VIRT_PLIC) };
    let hart_id: usize = 0;
    let supervisor = IntrTargetPriority::Supervisor;
    let machine = IntrTargetPriority::Machine;
    plic.set_threshold(hart_id, supervisor, 0);
    plic.set_threshold(hart_id, machine, 1);
    // irq nums: 5 keyboard, 6 mouse, BLOCK_IRQ, UART_IRQ, net_irq
    // basic 阶段只启用 block + uart + net，键盘/鼠标已注释掉 lazy init
    let block_irq = crate::arch::virtio::block_irq();
    let block_irq2 = crate::arch::virtio::block_irq2();
    let net_irq = crate::arch::virtio::net_irq();
    for intr_src_id in [block_irq, UART_IRQ, net_irq] {
        plic.enable(hart_id, supervisor, intr_src_id);
        plic.set_priority(intr_src_id, 1);
    }
    // 第二 block 设备 (vdb/x1) 若存在则启用其 IRQ
    if block_irq2 != 0 {
        plic.enable(hart_id, supervisor, block_irq2);
        plic.set_priority(block_irq2, 1);
    }

    // IRQ 全局使能推迟到 add_initproc 之后，启动阶段的块设备/文件系统操作使用同步轮询。
}

// 目前中断处理不是统一的trait，后面可以优化

pub fn irq_handler() {
    let mut plic = unsafe { PLIC::new(VIRT_PLIC) };
    let intr_src_id = plic.claim(0, IntrTargetPriority::Supervisor);
    // polyhal::println!("  [board] irq_handler: claimed source={}", intr_src_id);
    let block_irq = crate::arch::virtio::block_irq() as u32;
    let block_irq2 = crate::arch::virtio::block_irq2() as u32;
    match intr_src_id {
        // 5 => KEYBOARD_DEVICE.handle_irq(),
        // 6 => MOUSE_DEVICE.handle_irq(),
        x if x == block_irq => {
            crate::arch::block::handle_claimed_irq(&mut plic, intr_src_id);
            return;
        }
        x if x == UART_IRQ as u32 => UART.handle_irq(),
        //不需要网卡驱动 使用net模块的handle
        x if x == crate::arch::virtio::net_irq() as u32 => crate::net::net_interrupt_handler(),
        x if x == block_irq2 && block_irq2 != 0 => {
            crate::arch::block::handle_claimed_irq_vdb(&mut plic, intr_src_id);
            return;
        }
        _ => {}
    }
    plic.complete(0, IntrTargetPriority::Supervisor, intr_src_id);
}

use core::ptr::NonNull;
use core::sync::atomic::AtomicUsize;

use virtio_drivers::transport::mmio::{MmioTransport, VirtIOHeader};
use virtio_drivers::transport::{DeviceType, Transport};

pub type BlockTransport = MmioTransport;
pub type NetTransport = MmioTransport;

const VIRTIO_MMIO_BASE: usize = 0x1000_1000;
const VIRTIO_MMIO_STRIDE: usize = 0x1000;
const VIRTIO_MMIO_COUNT: usize = 8;
const MMIO_INTERRUPT_STATUS_OFFSET: usize = 0x60;

/// block 设备的 MMIO 物理基地址，由 scan 时设置
static BLOCK_MMIO_BASE: AtomicUsize = AtomicUsize::new(0x1000_8000);
/// 第二个 block 设备的 MMIO 物理基地址（x1/disk.img），由 scan 时设置
static BLOCK_MMIO_BASE2: AtomicUsize = AtomicUsize::new(0);
/// net 设备的 MMIO 物理基地址，由 scan 时设置
static NET_MMIO_BASE: AtomicUsize = AtomicUsize::new(0x1000_7000);

pub struct BlockDeviceAccess {
    pub transport: BlockTransport,
    pub irq_line: Option<usize>,
    pub mmio_base: usize,
}

pub struct NetDeviceAccess {
    pub transport: NetTransport,
    pub irq_line: Option<usize>,
    pub mmio_base: usize,
}

/// 安全的设备探测：创建 MmioTransport 读取设备类型，若不需要则 forget 避免 Drop 重置设备。
///
/// MmioTransport::new() 仅读取 magic / device_id / version 寄存器（无副作用），
/// 但 Drop 会写 status=0 触发设备复位。对已初始化的设备（如 VirtIOBlk），
/// 复位会破坏已协商的特性、virtqueue 地址等，导致后续 I/O 失败或 page fault。
/// 因此对不打算使用的设备，必须 forget 其 transport 阻止 Drop。
fn try_create_transport(base: usize) -> Option<MmioTransport> {
    let header = NonNull::new((base | polyhal::consts::VIRT_ADDR_START) as *mut VirtIOHeader)?;
    // SAFETY: header 指向有效的 MMIO 区域，transport 仅读取寄存器无副作用。
    unsafe { MmioTransport::new(header) }.ok()
}

/// 一次扫描找到前两个 Block 设备（0→7，低 bus 优先）。
/// 官方平台 bus.0=sdcard 须作为 VDA 根文件系统。
pub fn new_block_device() -> BlockDeviceAccess {
    let mut first: Option<(MmioTransport, usize)> = None;
    let mut second_base: usize = 0;

    for i in 0..VIRTIO_MMIO_COUNT {
        let base = VIRTIO_MMIO_BASE + i * VIRTIO_MMIO_STRIDE;
        let Some(transport) = try_create_transport(base) else {
            continue;
        };
        if transport.device_type() == DeviceType::Block {
            if first.is_none() {
                polyhal::println!("[virtio] probe Block at mmio=0x{:x}", base);
                first = Some((transport, base));
            } else if second_base == 0 {
                polyhal::println!("[virtio] second Block at mmio=0x{:x}", base);
                second_base = base;
                // transport 已创建但我们不在此处使用它——
                // new_second_block_device() 会创建新的 transport。
                // forget 它以阻止 Drop 复位设备。
                core::mem::forget(transport);
                break;
            }
        } else if transport.device_type() == DeviceType::Network {
            // 记录 net 设备的 MMIO 基地址，供 device_init() 在 step [4] 使用正确的 IRQ。
            NET_MMIO_BASE.store(base, core::sync::atomic::Ordering::Relaxed);
            core::mem::forget(transport);
        } else {
            core::mem::forget(transport);
        }
    }

    BLOCK_MMIO_BASE2.store(second_base, core::sync::atomic::Ordering::Relaxed);

    let (transport, base) = first.expect("no virtio block device found in MMIO region");
    BLOCK_MMIO_BASE.store(base, core::sync::atomic::Ordering::Relaxed);
    polyhal::println!("[virtio] block device at mmio=0x{:x}", base);
    BlockDeviceAccess {
        transport,
        irq_line: None,
        mmio_base: base,
    }
}

/// 创建第二个 block 设备（x1/disk.img），直接用缓存的地址，不重新扫描。
pub fn new_second_block_device() -> Option<BlockDeviceAccess> {
    let base = BLOCK_MMIO_BASE2.load(core::sync::atomic::Ordering::Relaxed);
    if base == 0 {
        return None;
    }
    let transport = try_create_transport(base)?;
    Some(BlockDeviceAccess {
        transport,
        irq_line: None,
        mmio_base: base,
    })
}

/// 扫描并创建 net 设备。不想要的其他类型 device transport 会被 forget 避免复位。
pub fn new_net_device() -> NetDeviceAccess {
    for i in 0..VIRTIO_MMIO_COUNT {
        let base = VIRTIO_MMIO_BASE + i * VIRTIO_MMIO_STRIDE;
        let Some(transport) = try_create_transport(base) else {
            continue;
        };
        if transport.device_type() == DeviceType::Network {
            NET_MMIO_BASE.store(base, core::sync::atomic::Ordering::Relaxed);
            polyhal::println!("[virtio] net device at mmio=0x{:x}", base);
            return NetDeviceAccess {
                transport,
                irq_line: None,
                mmio_base: base,
            };
        }
        // 不是 Network → forget，避免 Drop 复位已初始化的 Block 设备
        core::mem::forget(transport);
    }
    // 无网络设备 — 由于 main.rs 中跳过了 net::init()，此处不可达
    panic!("no virtio net device found in MMIO region");
}

const VIRTIO_IRQ_BASE: usize = 1;

pub fn block_irq() -> usize {
    let base = BLOCK_MMIO_BASE.load(core::sync::atomic::Ordering::Relaxed);
    VIRTIO_IRQ_BASE + (base.saturating_sub(VIRTIO_MMIO_BASE)) / VIRTIO_MMIO_STRIDE
}

pub fn block_irq2() -> usize {
    let base = BLOCK_MMIO_BASE2.load(core::sync::atomic::Ordering::Relaxed);
    if base == 0 {
        return 0;
    }
    VIRTIO_IRQ_BASE + (base.saturating_sub(VIRTIO_MMIO_BASE)) / VIRTIO_MMIO_STRIDE
}

pub fn net_irq() -> usize {
    let base = NET_MMIO_BASE.load(core::sync::atomic::Ordering::Relaxed);
    VIRTIO_IRQ_BASE + (base.saturating_sub(VIRTIO_MMIO_BASE)) / VIRTIO_MMIO_STRIDE
}

pub fn block_interrupt_status() -> u32 {
    use core::ptr::read_volatile;

    let base = BLOCK_MMIO_BASE.load(core::sync::atomic::Ordering::Relaxed);
    let interrupt_status_ptr =
        ((base | polyhal::consts::VIRT_ADDR_START) + MMIO_INTERRUPT_STATUS_OFFSET)
            as *const u32;
    unsafe { read_volatile(interrupt_status_ptr) }
}

pub fn net_interrupt_status() -> u32 {
    use core::ptr::read_volatile;

    let base = NET_MMIO_BASE.load(core::sync::atomic::Ordering::Relaxed);
    let interrupt_status_ptr =
        ((base | polyhal::consts::VIRT_ADDR_START) + MMIO_INTERRUPT_STATUS_OFFSET)
            as *const u32;
    unsafe { read_volatile(interrupt_status_ptr) }
}

//! eventfd — Linux eventfd(2) 实现。
//!
//! 一个带 64 位计数器的 fd 对象：write 累加计数器，read 获取并清零。
//! 内核用它替代 pipe 做事件通知——无需 byte buffer，单 inode 而非管道对，开销更低。
//!
//! Semantics:
//! - read(2): 返回 8 字节计数器值，清零（semaphore 模式下减 1，返回 1）
//! - write(2): 将 8 字节值累加到计数器，上限 u64::MAX-1
//! - 计数器为 0 时 read 阻塞（O_NONBLOCK → EAGAIN）
//! - 计数器即将溢出时 write 阻塞（O_NONBLOCK → EAGAIN）

use alloc::sync::Arc;

use filesystem::vfs_defs::{InodeMode, InodeOps, Kstat, PollEvents, VfsError, VfsRet};

use crate::sync::{Condvar, UPSafeCellRaw};
use crate::task::{current_task, schedule};

struct EventFdInner {
    counter: u64,
    /// Readers wait here when counter == 0; writers wait when counter is near max.
    wait: Condvar,
}

pub struct EventFd {
    inner: Arc<UPSafeCellRaw<EventFdInner>>,
    semaphore: bool,
    nonblock: bool,
}

impl InodeOps for EventFd {
    fn read_at(&self, _offset: usize, buf: &mut [u8]) -> VfsRet<usize> {
        if buf.len() < 8 {
            return Err(VfsError::InvalidInput);
        }
        loop {
            let mut inner = self.inner.get_mut();
            if inner.counter > 0 {
                let val = if self.semaphore {
                    inner.counter -= 1;
                    1u64
                } else {
                    let v = inner.counter;
                    inner.counter = 0;
                    v
                };
                // 释放了计数器空间，唤醒可能阻塞的 writer
                inner.wait.signal();
                buf[..8].copy_from_slice(&val.to_ne_bytes());
                return Ok(8);
            }
            if self.nonblock {
                return Err(VfsError::WouldBlock);
            }
            // 竞态安全阻塞：入队 → 重检 → 阻塞
            let task = inner.wait.enqueue_current();
            {
                let inner = self.inner.get_mut();
                if inner.counter > 0 {
                    inner.wait.dequeue(&task);
                    continue;
                }
            }
            let kc_ptr = self.inner.get_mut().wait.block_no_sched();
            schedule(kc_ptr.cast());
        }
    }

    fn write_at(&self, _offset: usize, buf: &[u8]) -> VfsRet<usize> {
        if buf.len() < 8 {
            return Err(VfsError::InvalidInput);
        }
        let add = u64::from_ne_bytes(buf[..8].try_into().unwrap());
        // Linux: writing 0xffffffffffffffff → EINVAL
        if add == u64::MAX {
            return Err(VfsError::InvalidInput);
        }
        let max = u64::MAX - 1;
        loop {
            let mut inner = self.inner.get_mut();
            if inner.counter <= max - add {
                inner.counter += add;
                inner.wait.signal(); // 唤醒阻塞的 reader
                return Ok(8);
            }
            if self.nonblock {
                return Err(VfsError::WouldBlock);
            }
            let task = inner.wait.enqueue_current();
            {
                let inner = self.inner.get_mut();
                if inner.counter <= max - add {
                    inner.wait.dequeue(&task);
                    continue;
                }
            }
            let kc_ptr = self.inner.get_mut().wait.block_no_sched();
            schedule(kc_ptr.cast());
        }
    }

    fn poll(&self, events: PollEvents) -> PollEvents {
        let mut result = PollEvents::empty();
        let inner = self.inner.get_mut();
        if inner.counter > 0 {
            result |= PollEvents::POLLIN;
        }
        if inner.counter < u64::MAX - 1 {
            result |= PollEvents::POLLOUT;
        }
        result & events
    }

    fn get_mode(&self) -> VfsRet<InodeMode> {
        Ok(InodeMode::S_IFIFO | InodeMode::S_IRUSR | InodeMode::S_IWUSR)
    }

    fn get_size(&self) -> VfsRet<usize> {
        Ok(0)
    }

    fn get_attr(&self) -> VfsRet<Kstat> {
        Ok(Kstat {
            st_mode: (InodeMode::S_IFIFO | InodeMode::S_IRUSR | InodeMode::S_IWUSR).bits(),
            st_nlink: 1,
            st_blksize: 4096,
            ..Default::default()
        })
    }
}

/// 创建 eventfd 实例。
pub fn create_eventfd(initval: u64, semaphore: bool, nonblock: bool) -> Arc<EventFd> {
    Arc::new(EventFd {
        inner: Arc::new(unsafe {
            UPSafeCellRaw::new(EventFdInner {
                counter: initval,
                wait: Condvar::new(),
            })
        }),
        semaphore,
        nonblock,
    })
}

