#[cfg(any(debug_assertions, feature = "cache_stats"))]
mod cache_stat {
    use core::sync::atomic::{AtomicU64, Ordering};

    pub(super) static FILE_HIT:  AtomicU64 = AtomicU64::new(0);
    pub(super) static FILE_MISS: AtomicU64 = AtomicU64::new(0);
    pub(super) static BLOCK_HIT:  AtomicU64 = AtomicU64::new(0);
    pub(super) static BLOCK_MISS: AtomicU64 = AtomicU64::new(0);

    pub(super) fn inc_file_hit()    { FILE_HIT.fetch_add(1, Ordering::Relaxed); }
    pub(super) fn inc_file_miss()   { FILE_MISS.fetch_add(1, Ordering::Relaxed); }
    pub(super) fn inc_block_hit()   { BLOCK_HIT.fetch_add(1, Ordering::Relaxed); }
    pub(super) fn inc_block_miss()  { BLOCK_MISS.fetch_add(1, Ordering::Relaxed); }

    pub(super) fn file_hits()   -> u64 { FILE_HIT.load(Ordering::Relaxed) }
    pub(super) fn file_misses() -> u64 { FILE_MISS.load(Ordering::Relaxed) }
    pub(super) fn block_hits()  -> u64 { BLOCK_HIT.load(Ordering::Relaxed) }
