//  Page — 数据唯一存储单元
// ============================================================

/// 4KB 内存页，文件数据和元数据共享同一个 Page 结构，
/// 由统一 `PAGE_CACHE` 管理。
///
/// `dirty` 标志仅对文件数据页有意义：
/// `mmap(MAP_SHARED)` 写入和 regular file 的保守 writeback 会显式标脏，
/// 最终由 `file_page_sync*` / `fsync` / `msync` / `munmap` 等路径写回。
/// 元数据页不使用该标志。
pub struct Page {
    data: NonNull<u8>,
    lock: MutexSpin,
    pub dirty: AtomicBool,
    /// 页面内容版本号。
    /// mmap 脏写和 regular file 的 writeback 写入会通过 `mark_dirty()`
    /// 递增，
    /// 以便回写线程检测“snapshot 后又被改写”的情况并重试。
    dirty_seq: AtomicUsize,
}

unsafe impl Send for Page {}
unsafe impl Sync for Page {}

impl Page {
    pub fn new() -> Self {
        let layout = Layout::from_size_align(PAGE_SIZE, PAGE_SIZE).unwrap();
        let ptr = unsafe { alloc_zeroed(layout) };
        if ptr.is_null() {
            handle_alloc_error(layout);
        }
        Self {
            data: NonNull::new(ptr).unwrap(),
            lock: MutexSpin::new(),
            dirty: AtomicBool::new(false),
            dirty_seq: AtomicUsize::new(0),
        }
    }
    pub fn as_slice(&self) -> &[u8] {
        unsafe { core::slice::from_raw_parts(self.data.as_ptr(), PAGE_SIZE) }
    }
    pub fn as_mut_slice(&mut self) -> &mut [u8] {
        unsafe { core::slice::from_raw_parts_mut(self.data.as_ptr(), PAGE_SIZE) }
    }
    pub fn phys_addr(&self) -> usize {
        (self.data.as_ptr() as usize) - polyhal::consts::VIRT_ADDR_START
    }

    fn raw_slice(&self) -> &[u8] {
        unsafe { core::slice::from_raw_parts(self.data.as_ptr(), PAGE_SIZE) }
    }

    pub fn copy_out(&self, offset: usize, dst: &mut [u8]) {
        self.lock.lock();
        dst.copy_from_slice(&self.raw_slice()[offset..offset + dst.len()]);
        self.lock.unlock();
    }

    pub fn copy_out_with_seq(&self, offset: usize, dst: &mut [u8]) -> usize {
        self.lock.lock();
        dst.copy_from_slice(&self.raw_slice()[offset..offset + dst.len()]);
        let seq = self.dirty_seq.load(Ordering::Acquire);
        self.lock.unlock();
        seq
    }

    pub fn overwrite_full(&self, data: &[u8]) {
        debug_assert_eq!(data.len(), PAGE_SIZE);
        self.lock.lock();
        unsafe {
            core::ptr::copy_nonoverlapping(data.as_ptr(), self.data.as_ptr(), PAGE_SIZE);
        }
        self.dirty_seq.fetch_add(1, Ordering::AcqRel);
        self.lock.unlock();
    }

    pub fn write_range(&self, offset: usize, data: &[u8]) {
        self.lock.lock();
        unsafe {
            core::ptr::copy_nonoverlapping(
                data.as_ptr(),
                self.data.as_ptr().add(offset),
                data.len(),
            );
        }
        self.dirty_seq.fetch_add(1, Ordering::AcqRel);
        self.lock.unlock();
    }

    pub fn fill_zero_range(&self, start: usize, end: usize) {
        self.lock.lock();
        unsafe {
            core::ptr::write_bytes(self.data.as_ptr().add(start), 0, end - start);
        }
        self.dirty_seq.fetch_add(1, Ordering::AcqRel);
        self.lock.unlock();
    }

    pub fn snapshot(&self) -> Vec<u8> {
        let mut out = alloc::vec![0u8; PAGE_SIZE];
        self.copy_out(0, out.as_mut_slice());
        out
    }

    pub fn mark_dirty(&self) {
        self.dirty.store(true, Ordering::Release);
        self.dirty_seq.fetch_add(1, Ordering::AcqRel);
    }

    pub fn dirty_seq(&self) -> usize {
        self.dirty_seq.load(Ordering::Acquire)
    }
}

impl Drop for Page {
    fn drop(&mut self) {
        let layout = Layout::from_size_align(PAGE_SIZE, PAGE_SIZE).unwrap();
        unsafe { dealloc(self.data.as_ptr(), layout) };
    }
}

