/// 以块为单位进行读写的块设备抽象。
///
/// 此 trait 独立于 VFS 层，由块设备驱动 (如 VirtIO) 实现，
/// 供文件系统或缓冲层通过统一的设备注册表使用。
pub trait BlockDevice: Send + Sync {
    /// 从指定的块号 `block_id` 读取一整块数据到缓冲区 `buf` 中。
    /// 调用者需确保 `buf` 长度与设备块大小一致。
    fn read_block(&self, block_id: usize, buf: &mut [u8]);

    /// 从指定块号开始连续读取多个扇区到 `buf` 中。
    ///
    /// 默认实现退化为逐扇区调用 `read_block`，支持批量 DMA 的设备应覆盖该方法。
    fn read_blocks(&self, block_id: usize, buf: &mut [u8]) {
        assert_ne!(buf.len(), 0);
        assert_eq!(buf.len() % SECTOR_SIZE, 0);
        for (idx, chunk) in buf.chunks_mut(SECTOR_SIZE).enumerate() {
            self.read_block(block_id + idx, chunk);
        }
    }

    /// 将缓冲区 `buf` 中的数据写入到指定的块号 `block_id`。
    /// 调用者需确保 `buf` 长度与设备块大小一致。
    fn write_block(&self, block_id: usize, buf: &[u8]);

    /// 从指定块号开始连续写入多个扇区。
    ///
    /// 默认实现退化为逐扇区调用 `write_block`，支持批量 DMA 的设备应覆盖该方法。
    fn write_blocks(&self, block_id: usize, buf: &[u8]) {
        assert_ne!(buf.len(), 0);
        assert_eq!(buf.len() % SECTOR_SIZE, 0);
        for (idx, chunk) in buf.chunks(SECTOR_SIZE).enumerate() {
            self.write_block(block_id + idx, chunk);
        }
    }

    /// 返回设备总扇区数（512-byte sectors），未知时返回 `None`。
    fn sector_count(&self) -> Option<usize> {
        None
    }
}

const MBR_PARTITION_TABLE_OFFSET: usize = 446;
const MBR_PARTITION_ENTRY_SIZE: usize = 16;
const MBR_PARTITION_COUNT: usize = 4;

#[derive(Clone, Debug)]
pub struct MbrPartition {
    /// 分区号，按 MBR 主分区表顺序从 1 开始。
    pub index: usize,
    pub partition_type: u8,
    pub start_lba: usize,
    pub sector_count: usize,
}

/// 逻辑分区设备包装器，将父设备的某个连续 LBA 范围暴露为独立块设备。
pub struct PartitionBlockDevice {
    parent: Arc<dyn BlockDevice>,
    start_lba: usize,
    sector_count: usize,
}

impl PartitionBlockDevice {
    pub fn new(parent: Arc<dyn BlockDevice>, start_lba: usize, sector_count: usize) -> Self {
        Self {
            parent,
            start_lba,
            sector_count,
        }
    }
}

impl BlockDevice for PartitionBlockDevice {
    fn read_block(&self, block_id: usize, buf: &mut [u8]) {
        if buf.len() != SECTOR_SIZE || block_id >= self.sector_count {
            buf.fill(0);
            return;
        }
        self.parent.read_block(self.start_lba + block_id, buf);
    }

    fn read_blocks(&self, block_id: usize, buf: &mut [u8]) {
        if buf.is_empty()
            || buf.len() % SECTOR_SIZE != 0
            || block_id.saturating_add(buf.len() / SECTOR_SIZE) > self.sector_count
        {
            buf.fill(0);
            return;
        }
        self.parent.read_blocks(self.start_lba + block_id, buf);
    }

    fn write_block(&self, block_id: usize, buf: &[u8]) {
        if buf.len() != SECTOR_SIZE || block_id >= self.sector_count {
            return;
        }
        self.parent.write_block(self.start_lba + block_id, buf);
    }

    fn write_blocks(&self, block_id: usize, buf: &[u8]) {
        if buf.is_empty()
            || buf.len() % SECTOR_SIZE != 0
            || block_id.saturating_add(buf.len() / SECTOR_SIZE) > self.sector_count
        {
            return;
        }
        self.parent.write_blocks(self.start_lba + block_id, buf);
    }

    fn sector_count(&self) -> Option<usize> {
        Some(self.sector_count)
    }
}

