    ///
    /// 注册时自动分配全局唯一的 `dev_id`，用于 `PAGE_CACHE` 缓存 key。
    pub static ref BLOCK_DEVICES: UPIntrFreeCell<BTreeMap<String, BlockDeviceEntry>> =
        unsafe { UPIntrFreeCell::with_name(BTreeMap::new(), "BLOCK_DEVICES") };
}

pub fn register_block_device(name: &str, device: Arc<dyn BlockDevice>) -> usize {
