}

/// 扫描 MBR 主分区表并返回所有有效主分区。
///
/// 当前只处理传统 MBR 的 4 个主分区项，足以覆盖 `/dev/vda2` 这类基本评测场景。
/// 若后续要支持 GPT/扩展分区，可在此基础上继续扩展。
pub fn scan_mbr_partitions(device: Arc<dyn BlockDevice>) -> Option<Vec<MbrPartition>> {
    let mut sector = [0u8; SECTOR_SIZE];
    device.read_block(0, &mut sector);

    if sector[510] != 0x55 || sector[511] != 0xAA {
        return None;
    }

    let device_sectors = device.sector_count();
    let mut partitions = Vec::new();
    for entry_idx in 0..MBR_PARTITION_COUNT {
        let off = MBR_PARTITION_TABLE_OFFSET + entry_idx * MBR_PARTITION_ENTRY_SIZE;
        let partition_type = sector[off + 4];
        let start_lba = u32::from_le_bytes([
            sector[off + 8],
            sector[off + 9],
            sector[off + 10],
            sector[off + 11],
        ]) as usize;
        let sector_count = u32::from_le_bytes([
            sector[off + 12],
            sector[off + 13],
            sector[off + 14],
            sector[off + 15],
        ]) as usize;

        if partition_type == 0 || sector_count == 0 {
            continue;
        }

        let end_lba = match start_lba.checked_add(sector_count) {
            Some(end) => end,
            None => continue,
        };
        if let Some(total) = device_sectors {
            if start_lba >= total || end_lba > total {
                continue;
            }
        }

        partitions.push(MbrPartition {
            index: entry_idx + 1,
            partition_type,
            start_lba,
            sector_count,
        });
    }

    Some(partitions)
}

