/// `Ext4FileSystem` 实现了 `FileSystemType` trait，用于 VFS 管理层的统一挂载调用。
pub struct Ext4FileSystem;

impl FileSystemType for Ext4FileSystem {
    fn name(&self) -> &str {
        "ext4"
    }

    /// 挂载 Ext4 文件系统
    /// - `dev_name`: 注册在 `device::BLOCK_DEVICES` 中的块设备名称 (例如 "/dev/vda")
    /// - `_data`: 挂载参数 (当前未使用)
    fn mount(&self, dev_name: &str, _data: &str) -> VfsRet<Arc<dyn SuperBlock>> {
        // 1. 根据 dev_name 从全局设备表中获取对应的块设备实例及 dev_id
        let entry = get_block_device(dev_name).ok_or(VfsError::DeviceError)?;
        let device = entry.device;
        let dev_id = entry.dev_id;

        // 2. 创建 Ext4Device 适配器，外包裹 CachedBlockDevice 提供块级页缓存。
        //    所有 ext4_rs 内部 I/O（inode表、目录块、位图、超级块等）都经过此缓存层。
        //    CachedBlockDevice 使用统一 PAGE_CACHE（fs_id=0 命名空间），
        //    与文件数据页（fs_id>0）共用同一 LRU。
        let cached_dev = Arc::new(CachedBlockDevice::new(device, dev_id));
        let ext4_disk = Arc::new(Ext4Device::new(cached_dev));

        // 3. 使用 ext4_rs 库提供的 open 接口解析超级块，初始化 Ext4 文件系统实例，
        //    并为本次挂载分配全局唯一的 fs_id。二者封装为 Arc<Ext4Fs>，同一挂载点的
        //    所有 Ext4Inode 共享此句柄。
        let ext4 = Ext4::open(ext4_disk);
        let fs_id = next_fs_id();
        let fs = Arc::new(Ext4Fs::new(ext4, fs_id));

        // 4. 构建 ext4 文件系统的根 Inode（Ext4 规范中，根目录 Inode 编号固定为 ROOT_INODE = 2）
        let root_inode = Inode::from_arc_ops(Arc::new(Ext4Inode::new(fs.clone(), ROOT_INODE)));

        Ok(Arc::new(Ext4SuperBlock {
            _fs: fs,
            root_inode,
        }))
    }
}

pub struct Ext4SuperBlock {
    _fs: Arc<Ext4Fs>,
    root_inode: Arc<Inode>,
}

impl SuperBlock for Ext4SuperBlock {
    fn root_inode(&self) -> Arc<Inode> {
        self.root_inode.clone()
    }

    fn sync(&self) -> VfsRet<()> {
        sync_ext4_fs(&self._fs)
    }

    fn sync_inode(&self, ino: u64) -> VfsRet<()> {
        Inode::from_arc_ops(Arc::new(Ext4Inode::new(self._fs.clone(), ino as u32))).sync_data()
    }
}

