pub fn into_mcontext(trap_cx: &TrapFrame, u_sepc: usize) -> MachineContext {
    let mut mc = MachineContext {
        gp: GeneralRegs { x: trap_cx.x },
        fp: FloatRegs::default(),
    };
    // SEPC may have been advanced by syscall_ok() (e.g. ecall → ecall+4).
    // Expose the original trapped instruction address so that user-space handlers
    // (notably musl cancel_handler) can correctly check whether the interrupted PC
    // lies within a cancellation-point range [__cp_begin, __cp_end).
    mc.gp.x[0] = u_sepc.saturating_sub(4);
    mc
}

