pub fn from_elf(
    info: &super::elf::ElfInfo,
    elf_data: &[u8],
) -> (Self, usize, usize) {
    let loader = |offset: u64, buf: &mut [u8]| -> usize {
        let start = offset as usize;
        let end = (offset + buf.len() as u64).min(elf_data.len() as u64) as usize;
        let len = end.saturating_sub(start);
        buf[..len].copy_from_slice(&elf_data[start..end]);
        len
    };
    Self::from_elf_file(info, &loader)
}

/// 与 `from_elf` 功能相同，但按段从文件按需读取数据，避免将整个 ELF 文件
/// 读入内核堆。适用于 exec 路径，显著减少内核堆消耗。
///
/// `file_data` 提供 `(offset, buf) -> read_len` 能力：对每个 PT_LOAD 段，
/// 按其 p_offset/p_filesz 从文件读取数据到提供的缓冲区。
pub fn from_elf_file<F>(
    info: &super::elf::ElfInfo,
    file_data: &F,
) -> (Self, usize, usize)
where
    F: Fn(u64, &mut [u8]) -> usize,
{
    let mut memory_set = Self::new_bare();

    for (_si, seg) in info.segments.iter().enumerate() {
        let start_va: VirtAddr = seg.vaddr.into();
        let end_va: VirtAddr = (seg.vaddr + seg.memsz).into();
        let mut map_area = MapArea::new(start_va, end_va, MapType::Framed, seg.flags);
        map_area.map(&memory_set.page_table);

        // 按页从文件读取段数据
        let filesz = seg.filesz as usize;
        if filesz > 0 {
            let offset = seg.offset;
            let mut loaded = 0usize;
            let mut buf = alloc::vec![0u8; PAGE_SIZE];
            while loaded < filesz {
                let chunk = filesz.min(loaded + buf.len()) - loaded;
                let n = file_data(offset + loaded as u64, &mut buf[..chunk]);
                if n == 0 { break; }
                map_area.copy_data(
                    &memory_set.page_table,
                    VirtAddr::new(seg.vaddr + loaded),
                    &buf[..n],
                );
                loaded += n;
            }
        }

        // frame_alloc 不保证零初始化：显式将 .bss 区域填零。
        let bss_start = seg.vaddr + filesz as usize;
        let bss_len = seg.memsz as usize - filesz;
        if bss_len > 0 {
            let zero_buf = alloc::vec![0u8; bss_len.min(PAGE_SIZE)];
            let mut done = 0usize;
            while done < bss_len {
                let chunk = bss_len.min(done + zero_buf.len()) - done;
                map_area.copy_data(
                    &memory_set.page_table,
                    VirtAddr::new(bss_start + done),
