use crate::{Mutex, TaskHandle, UPIntrFreeCell, interrupt_free, task_ops};
use alloc::{collections::VecDeque, sync::Arc};

pub struct Condvar {
    pub inner: UPIntrFreeCell<CondvarInner>,
}

pub struct CondvarInner {
    pub wait_queue: VecDeque<TaskHandle>,
}

impl Condvar {
    pub fn new() -> Self {
        Self {
            inner: unsafe {
                UPIntrFreeCell::new(CondvarInner {
                    wait_queue: VecDeque::new(),
                })
            },
        }
    }

    pub fn signal(&self) {
        let mut inner = self.inner.exclusive_access();
        if let Some(task) = inner.wait_queue.pop_front() {
            (task_ops().wakeup_task)(task.into_raw());
        }
    }

    pub fn wait(&self) {
        let kc_ptr = self.wait_no_sched();
        (task_ops().set_current_block_reason)("condvar");
        (task_ops().schedule)(kc_ptr);
        (task_ops().clear_current_block_reason)();
    }

    pub fn broadcast(&self) {
        let mut inner = self.inner.exclusive_access();
        while let Some(task) = inner.wait_queue.pop_front() {
            (task_ops().wakeup_task)(task.into_raw());
        }
    }

    pub fn enqueue_current(&self) -> TaskHandle {
        let task = TaskHandle::current();
        self.inner.exclusive_session(|inner| {
            inner.wait_queue.push_back(task.clone());
        });
        task
    }

    pub fn dequeue(&self, task: &TaskHandle) {
        self.inner.exclusive_session(|inner| {
            inner.wait_queue.retain(|t| t != task);
        });
    }

    pub fn block_no_sched(&self) -> *mut () {
        (task_ops().block_current_task)()
    }

    pub fn wait_no_sched(&self) -> *mut () {
        self.inner.exclusive_session(|inner| {
            inner.wait_queue.push_back(TaskHandle::current());
        });
        self.block_no_sched()
    }

    pub fn wait_with_mutex(&self, mutex: Arc<dyn Mutex>) {
        // Make "unlock mutex -> enqueue waiter -> mark blocked" one interrupt-free
        // transition, otherwise signal() can slip in between and get lost.
        let kc_ptr = interrupt_free(|| {
            mutex.unlock();
            self.inner.exclusive_session(|inner| {
                inner.wait_queue.push_back(TaskHandle::current());
            });
            self.block_no_sched()
        });
        (task_ops().set_current_block_reason)("condvar");
        (task_ops().schedule)(kc_ptr);
        (task_ops().clear_current_block_reason)();
        mutex.lock();
    }
}

use crate::{TaskHandle, task_ops, UPIntrFreeCell};
use alloc::collections::VecDeque;

pub struct Semaphore {
    pub inner: UPIntrFreeCell<SemaphoreInner>,
}

pub struct SemaphoreInner {
    pub count: isize,
    pub wait_queue: VecDeque<TaskHandle>,
}

impl Semaphore {
    pub fn new(res_count: usize) -> Self {
        Self {
            inner: unsafe {
                UPIntrFreeCell::new(SemaphoreInner {
                    count: res_count as isize,
                    wait_queue: VecDeque::new(),
                })
            },
        }
    }

    pub fn up(&self) {
        let mut inner = self.inner.exclusive_access();
        inner.count += 1;
        if inner.count <= 0 {
            if let Some(task) = inner.wait_queue.pop_front() {
                (task_ops().wakeup_task)(task.into_raw());
            }
        }
    }

    pub fn down(&self) {
        let mut inner = self.inner.exclusive_access();
        inner.count -= 1;
        if inner.count < 0 {
            inner.wait_queue.push_back(TaskHandle::current());
            drop(inner);
            (task_ops().set_current_block_reason)("semaphore");
            (task_ops().block_current_and_run_next)();
            (task_ops().clear_current_block_reason)();
        }
    }
}

