        lose_net_stack::results::NetServerError::EmptyData
        | lose_net_stack::results::NetServerError::EmptyClient
        | lose_net_stack::results::NetServerError::Blocking => SyscallErrNo::EAGAIN,
        lose_net_stack::results::NetServerError::Unsupported => SyscallErrNo::ENOTCONN,
        lose_net_stack::results::NetServerError::NoUdpRemoteAddress => SyscallErrNo::EDESTADDRREQ,
        lose_net_stack::results::NetServerError::ServerNotExists
        | lose_net_stack::results::NetServerError::PortWasUsed => SyscallErrNo::EIO,
    }
}

