const AF_INET: usize = 2;

/// socket(2) — 创建 socket。
pub fn sys_socket(domain: usize, type_: usize, _protocol: usize) -> SyscallRet {
    if domain != AF_INET {
        return Err(SyscallErrNo::EAFNOSUPPORT);
    }
    let net_type = NetType::from_usize(type_ & 0xf).ok_or(SyscallErrNo::EINVAL)?;
    let socket = Socket::new(domain, net_type);

    let process = current_process();
    let inner = process.inner_exclusive_access();
    // SOCK_NONBLOCK → O_NONBLOCK on the new fd
    let file_flags = if type_ & SOCK_NONBLOCK != 0 {
        crate::fs::OpenFlags::O_NONBLOCK | crate::fs::OpenFlags::O_RDWR
    } else {
        crate::fs::OpenFlags::O_RDWR
    };
    let fd = inner.fd_table.get_mut().try_insert(Arc::new(VfsFile::new_dev_with_flags(Inode::from_arc_ops(socket), file_flags)))
        .ok_or(SyscallErrNo::EMFILE)?;

    if type_ & SOCK_CLOEXEC != 0 {
        inner.fd_table.get_mut().set_cloexec(fd, true);
    }

