pub type BlockDeviceImpl = crate::drivers::block::VirtIOBlock;
pub type CharDeviceImpl = crate::drivers::chardev::NS16550a<VIRT_UART>;

pub const VIRT_UART: usize = 0x9000_0000_1FE0_01E0;
pub const VIRT_PCH_PIC: usize = 0x9000_0000_1000_0000;
pub const VIRT_PCIE_ECAM: usize = 0x9000_0000_2000_0000;
pub const VIRT_PCIE_BAR_BASE: usize = 0x4000_0000;

// QEMU loongarch virt 的外设中断链路是
// PCH-PIC / PCH-MSI -> EXTIOI -> CPUINTC(HWI1)。
// 其中 UART 的本地 PCH-PIC 输入线是 2，PCI INTx 常落在 16..19。
pub const UART_IRQ: usize = 2;
// 兼容保底值：若 DTB/PCI 尚未解析到设备实际中断线，则回落到 QEMU virt 的
// INTx 默认窗口 16。
pub const BLOCK_IRQ: usize = 16;
pub const PCIE_IRQ_LAST: usize = 19;

use crate::drivers::chardev::{CharDevice, UART};
use loongArch64::iocsr::{iocsr_write_w, iocsr_read_w};

const PCH_PIC_INT_MASK_LO: usize = 0x20;
const PCH_PIC_INT_MASK_HI: usize = 0x24;
const PCH_PIC_INT_EDGE_LO: usize = 0x60;
const PCH_PIC_INT_EDGE_HI: usize = 0x64;
const PCH_PIC_ROUTE_ENTRY_OFFSET: usize = 0x100;
const PCH_PIC_HTMSI_VEC_OFFSET: usize = 0x200;
const PCH_PIC_INT_STATUS_LO: usize = 0x3a0;
const PCH_PIC_INT_STATUS_HI: usize = 0x3a4;
const PCH_PIC_INT_POL_LO: usize = 0x3e0;
const PCH_PIC_INT_POL_HI: usize = 0x3e4;

const EXTIOI_IPMAP0: usize = 0x14c0;
const EXTIOI_IPMAP1: usize = 0x14c4;
const EXTIOI_ENABLE_BASE: usize = 0x1600;
const EXTIOI_COREMAP_BASE: usize = 0x1c00;

const CPU0_MASK: u8 = 0x01;
const EXTIOI_ROUTE_TO_IP1: u8 = 0x02;
const PCIE_IRQ_MASK: u64 =
    ((1u64 << (PCIE_IRQ_LAST + 1)) - 1) & !((1u64 << BLOCK_IRQ) - 1);

#[inline]
fn irq_bit(irq: usize) -> u32 {
    1u32 << irq
}

#[inline]
fn block_irq_line() -> usize {
    crate::drivers::block::BLOCK_DEVICE.irq_line().unwrap_or(BLOCK_IRQ)
}

fn block_irq_mask() -> u64 {
    1u64 << block_irq_line()
}

fn vdb_irq_mask() -> u64 {
    crate::drivers::block::VDB_DEVICE
        .get()
        .and_then(|v| v.irq_line())
        .map(|irq| 1u64 << irq)
        .unwrap_or(0)
}

#[inline]
fn pch_pic_read_u32(offset: usize) -> u32 {
    let ptr = (VIRT_PCH_PIC + offset) as *const u32;
    unsafe { ptr.read_volatile() }
}

#[inline]
fn pch_pic_write_u32(offset: usize, value: u32) {
    let ptr = (VIRT_PCH_PIC + offset) as *mut u32;
    unsafe { ptr.write_volatile(value) }
}

#[inline]
fn pch_pic_write_u8(offset: usize, value: u8) {
    let ptr = (VIRT_PCH_PIC + offset) as *mut u8;
    unsafe { ptr.write_volatile(value) }
}

#[inline]
fn extioi_read_u32(offset: usize) -> u32 {
    iocsr_read_w(offset)
}

#[inline]
fn extioi_write_u32(offset: usize, value: u32) {
    iocsr_write_w(offset, value);
}

#[inline]
fn pch_pic_mask_offset(irq: usize) -> usize {
    if irq < 32 {
        PCH_PIC_INT_MASK_LO
    } else {
        PCH_PIC_INT_MASK_HI
    }
}

#[inline]
fn pch_pic_edge_offset(irq: usize) -> usize {
    if irq < 32 {
        PCH_PIC_INT_EDGE_LO
    } else {
        PCH_PIC_INT_EDGE_HI
    }
}

#[inline]
fn pch_pic_pol_offset(irq: usize) -> usize {
    if irq < 32 {
        PCH_PIC_INT_POL_LO
    } else {
        PCH_PIC_INT_POL_HI
    }
}

#[inline]
fn extioi_enable_offset(irq: usize) -> usize {
    EXTIOI_ENABLE_BASE + (irq / 32) * core::mem::size_of::<u32>()
}

#[inline]
fn extioi_coremap_offset(irq: usize) -> usize {
    EXTIOI_COREMAP_BASE + (irq / 4) * core::mem::size_of::<u32>()
}

#[inline]
fn extioi_route_all_to_ip1() {
    extioi_write_u32(EXTIOI_IPMAP0, 0x0202_0202);
    extioi_write_u32(EXTIOI_IPMAP1, 0x0202_0202);
}

fn extioi_route_irq_to_cpu0(irq: usize) {
    let offset = extioi_coremap_offset(irq);
    let shift = (irq % 4) * 8;
    let mut value = extioi_read_u32(offset);
    value &= !(0xff << shift);
    value |= (CPU0_MASK as u32) << shift;
    extioi_write_u32(offset, value);
}

fn extioi_enable_irq(irq: usize) {
    let offset = extioi_enable_offset(irq);
    let bit = 1u32 << (irq % 32);
    let value = extioi_read_u32(offset) | bit;
    extioi_write_u32(offset, value);
}

fn pch_pic_set_identity_vector(irq: usize) {
    pch_pic_write_u8(PCH_PIC_HTMSI_VEC_OFFSET + irq, irq as u8);
    // QEMU 9.2 的 TCG 模型真正使用的是 HTMSI_VEC，但这里把 route entry
    // 同步成一致值，便于和 DT / Linux 驱动的语义保持一致。
    pch_pic_write_u8(PCH_PIC_ROUTE_ENTRY_OFFSET + irq, irq as u8);
}

fn pch_pic_set_level_high(irq: usize) {
    let bit = 1u32 << (irq % 32);
    let edge_offset = pch_pic_edge_offset(irq);
    let pol_offset = pch_pic_pol_offset(irq);
    pch_pic_write_u32(edge_offset, pch_pic_read_u32(edge_offset) & !bit);
    pch_pic_write_u32(pol_offset, pch_pic_read_u32(pol_offset) & !bit);
}

fn pch_pic_unmask_irq(irq: usize) {
    let bit = 1u32 << (irq % 32);
    let offset = pch_pic_mask_offset(irq);
    let value = pch_pic_read_u32(offset) & !bit;
    pch_pic_write_u32(offset, value);
}

fn pch_pic_pending() -> u64 {
    (pch_pic_read_u32(PCH_PIC_INT_STATUS_HI) as u64) << 32
        | pch_pic_read_u32(PCH_PIC_INT_STATUS_LO) as u64
}

fn setup_external_irq_line(irq: usize) {
    pch_pic_set_identity_vector(irq);
    pch_pic_set_level_high(irq);
    extioi_route_irq_to_cpu0(irq);
}

fn enable_external_irq_line(irq: usize) {
    setup_external_irq_line(irq);
    extioi_enable_irq(irq);
    pch_pic_unmask_irq(irq);
}

pub fn device_init() {
    // QEMU loongarch virt 通过 PCH-PIC / PCH-MSI -> EXTIOI -> CPUINTC(HWI1)
    // 送外部中断。当前仅启用 UART 与 PCI INTx 窗口，块设备完成事件再由
    // status 寄存器中的 pending bit 做精确判定。
    extioi_route_all_to_ip1();

    enable_external_irq_line(UART_IRQ);
    for irq in BLOCK_IRQ..=PCIE_IRQ_LAST {
        enable_external_irq_line(irq);
    }
    // QEMU virt 的外部中断经 EXTIOI 路由到 CPUINTC 的 HWI1。
    polyhal::irq::IRQ::irq_enable(loongArch64::register::estat::Interrupt::HWI1 as usize);
}

pub fn irq_handler() {
    let pending = pch_pic_pending();
    if pending & (1u64 << UART_IRQ) != 0 {
        UART.handle_irq();
    }
    let block_pending = pending & block_irq_mask() != 0;
    let vdb_pending = pending & vdb_irq_mask() != 0;
    let pcie_pending = pending & PCIE_IRQ_MASK != 0;
    if block_pending || pcie_pending || vdb_pending {
        crate::arch::block::handle_irq();
    }
}

use crate::config::{PAGE_SIZE, PAGE_SIZE_BITS};
use core::fmt::{self, Debug, Formatter};
pub use polyhal::{PhysAddr, VirtAddr};

/// Definitions

#[repr(C)]
#[derive(Copy, Clone, Ord, PartialOrd, Eq, PartialEq)]
pub struct PhysPageNum(pub usize);

#[repr(C)]
#[derive(Copy, Clone, Ord, PartialOrd, Eq, PartialEq)]
pub struct VirtPageNum(pub usize);

/// Debugging

impl Debug for PhysPageNum {
    fn fmt(&self, f: &mut Formatter<'_>) -> fmt::Result {
        f.write_fmt(format_args!("PPN:{:#x}", self.0))
    }
}

impl Debug for VirtPageNum {
    fn fmt(&self, f: &mut Formatter<'_>) -> fmt::Result {
        f.write_fmt(format_args!("VPN:{:#x}", self.0))
    }
}

// ─── PhysAddr extension ────────────────────────────────────

pub trait PhysAddrExt {
    fn floor_pn(&self) -> PhysPageNum;
    fn ceil_pn(&self) -> PhysPageNum;
}

impl PhysAddrExt for PhysAddr {
    fn floor_pn(&self) -> PhysPageNum {
        PhysPageNum(self.raw() >> PAGE_SIZE_BITS)
    }
    fn ceil_pn(&self) -> PhysPageNum {
        PhysPageNum((self.raw() + PAGE_SIZE - 1) >> PAGE_SIZE_BITS)
    }
}

// ─── PhysPageNum ───────────────────────────────────────────

impl From<usize> for PhysPageNum {
    fn from(v: usize) -> Self {
        Self(v >> PAGE_SIZE_BITS)
    }
}

impl From<PhysPageNum> for usize {
    fn from(v: PhysPageNum) -> Self {
        v.0
    }
}

impl From<PhysAddr> for PhysPageNum {
    fn from(v: PhysAddr) -> Self {
        assert_eq!(v.raw() & 0xfff, 0, "PhysAddr must be page-aligned");
        Self(v.raw() >> PAGE_SIZE_BITS)
    }
}

impl From<PhysPageNum> for PhysAddr {
    fn from(v: PhysPageNum) -> Self {
        PhysAddr::new(v.0 << PAGE_SIZE_BITS)
    }
}

impl PhysPageNum {
    pub fn get_bytes_array(&self) -> &'static mut [u8] {
        let pa: PhysAddr = (*self).into();
        unsafe { core::slice::from_raw_parts_mut(pa.get_mut_ptr::<u8>(), PAGE_SIZE) }
    }

    pub fn get_mut<T>(&self) -> &'static mut T {
        let pa: PhysAddr = (*self).into();
        unsafe { &mut *pa.get_mut_ptr::<T>() }
    }
}

// ─── VirtAddr extension ────────────────────────────────────

pub trait VirtAddrExt {
    fn floor_pn(&self) -> VirtPageNum;
    fn ceil_pn(&self) -> VirtPageNum;
}

impl VirtAddrExt for VirtAddr {
    fn floor_pn(&self) -> VirtPageNum {
        VirtPageNum(self.raw() >> PAGE_SIZE_BITS)
    }
    fn ceil_pn(&self) -> VirtPageNum {
        VirtPageNum((self.raw().wrapping_add(PAGE_SIZE - 1)) >> PAGE_SIZE_BITS)
    }
}

// ─── VirtPageNum ───────────────────────────────────────────

impl From<usize> for VirtPageNum {
    fn from(v: usize) -> Self {
        Self(v >> PAGE_SIZE_BITS)
    }
}

impl From<VirtPageNum> for usize {
    fn from(v: VirtPageNum) -> Self {
        v.0
    }
}

impl From<VirtAddr> for VirtPageNum {
    fn from(v: VirtAddr) -> Self {
        assert_eq!(v.raw() & 0xfff, 0, "VirtAddr must be page-aligned");
        Self(v.raw() >> PAGE_SIZE_BITS)
    }
}

impl From<VirtPageNum> for VirtAddr {
    fn from(v: VirtPageNum) -> Self {
        VirtAddr::new(v.0 << PAGE_SIZE_BITS)
    }
}

pub trait StepByOne {
    fn step(&mut self);
}
impl StepByOne for PhysPageNum {
    fn step(&mut self) {
        self.0 += 1;
    }
}
impl StepByOne for VirtPageNum {
    fn step(&mut self) {
        self.0 += 1;
    }
}

#[derive(Copy, Clone)]
pub struct SimpleRange<T>
where
    T: StepByOne + Copy + PartialEq + PartialOrd + Debug,
{
    l: T,
    r: T,
}
impl<T> SimpleRange<T>
where
    T: StepByOne + Copy + PartialEq + PartialOrd + Debug,
{
    pub fn new(start: T, end: T) -> Self {
        assert!(start <= end, "start {:?} > end {:?}!", start, end);
        Self { l: start, r: end }
    }
    pub fn get_start(&self) -> T {
        self.l
    }
    pub fn get_end(&self) -> T {
        self.r
    }
    pub fn set_start(&mut self, new_start: T) {
        assert!(new_start <= self.r, "new_start {:?} > end {:?}!", new_start, self.r);
        self.l = new_start;
    }
    pub fn set_end(&mut self, new_end: T) {
        assert!(new_end >= self.l, "new_end {:?} < start {:?}!", new_end, self.l);
        self.r = new_end;
    }
    pub fn contains(&self, item: T) -> bool {
        item >= self.l && item < self.r
    }
}
impl<T> IntoIterator for SimpleRange<T>
where
    T: StepByOne + Copy + PartialEq + PartialOrd + Debug,
{
    type Item = T;
    type IntoIter = SimpleRangeIterator<T>;
    fn into_iter(self) -> Self::IntoIter {
        SimpleRangeIterator::new(self.l, self.r)
    }
}
pub struct SimpleRangeIterator<T>
where
    T: StepByOne + Copy + PartialEq + PartialOrd + Debug,
{
    current: T,
    end: T,
}
impl<T> SimpleRangeIterator<T>
where
    T: StepByOne + Copy + PartialEq + PartialOrd + Debug,
{
    pub fn new(l: T, r: T) -> Self {
        Self { current: l, end: r }
    }
}
impl<T> Iterator for SimpleRangeIterator<T>
where
    T: StepByOne + Copy + PartialEq + PartialOrd + Debug,
{
    type Item = T;
    fn next(&mut self) -> Option<Self::Item> {
        if self.current == self.end {
            None
        } else {
            let t = self.current;
            self.current.step();
            Some(t)
        }
    }
}
pub type VPNRange = SimpleRange<VirtPageNum>;

