use core::cell::{RefCell, RefMut, UnsafeCell};
use core::ops::{Deref, DerefMut};
use lazy_static::*;
use crate::irq_ops;

#[cfg(feature = "lock_debug")]
use core::sync::atomic::{AtomicUsize, Ordering};

pub struct UPSafeCellRaw<T> {
    inner: UnsafeCell<T>,
}

unsafe impl<T> Sync for UPSafeCellRaw<T> {}

impl<T> UPSafeCellRaw<T> {
    pub unsafe fn new(value: T) -> Self {
        Self {
            inner: UnsafeCell::new(value),
        }
    }
    pub fn get_mut(&self) -> &mut T {
        unsafe { &mut (*self.inner.get()) }
    }
}

pub struct IntrMaskingInfo {
    nested_level: usize,
    sie_before_masking: bool,
}

lazy_static! {
    static ref INTR_MASKING_INFO: UPSafeCellRaw<IntrMaskingInfo> =
        unsafe { UPSafeCellRaw::new(IntrMaskingInfo::new()) };
}

impl IntrMaskingInfo {
    pub fn new() -> Self {
        Self {
            nested_level: 0,
            sie_before_masking: false,
        }
    }

    pub fn enter(&mut self) {
        let ops = irq_ops();
        let enabled = (ops.int_enabled)();
        (ops.int_disable)();
        if self.nested_level == 0 {
            self.sie_before_masking = enabled;
        }
        self.nested_level += 1;
    }

    pub fn exit(&mut self) {
        self.nested_level -= 1;
        if self.nested_level == 0 && self.sie_before_masking {
            (irq_ops().int_enable)();
        }
    }
}

// RAII guard for a nested interrupt-masking critical section.
// Used by interrupt_free() to keep multi-step state transitions atomic on UP.
struct IntrMaskGuard;

impl IntrMaskGuard {
    fn new() -> Self {
        INTR_MASKING_INFO.get_mut().enter();
        Self
    }
}

impl Drop for IntrMaskGuard {
    fn drop(&mut self) {
        INTR_MASKING_INFO.get_mut().exit();
    }
}

pub fn interrupt_free<F, V>(f: F) -> V
where
    F: FnOnce() -> V,
{
    // Keep interrupts masked for the whole closure so callers can compose
    // multiple lockless steps without reopening the wakeup window in between.
    let _guard = IntrMaskGuard::new();
    f()
}

pub struct UPIntrFreeCell<T> {
    inner: RefCell<T>,
    #[cfg(feature = "lock_debug")]
    name: &'static str,
    #[cfg(feature = "lock_debug")]
    holder_pc: AtomicUsize,
    #[cfg(feature = "lock_debug")]
    holder_loc: AtomicUsize,
}

unsafe impl<T> Sync for UPIntrFreeCell<T> {}

#[cfg(feature = "lock_debug")]
macro_rules! caller_pc {
    () => {{
        let pc: usize;
        #[cfg(target_arch = "riscv64")]
        unsafe { core::arch::asm!("mv {}, ra", out(reg) pc) };
        #[cfg(target_arch = "loongarch64")]
        unsafe { core::arch::asm!("move {}, $r1", out(reg) pc) };
        pc
    }};
}

#[cfg(feature = "lock_debug")]
pub struct UPIntrRefMut<'a, T>(
    Option<RefMut<'a, T>>,
    Option<&'a UPIntrFreeCell<T>>,
);

#[cfg(not(feature = "lock_debug"))]
pub struct UPIntrRefMut<'a, T>(Option<RefMut<'a, T>>);

impl<T> UPIntrFreeCell<T> {
    pub unsafe fn new(value: T) -> Self {
        Self {
            inner: RefCell::new(value),
            #[cfg(feature = "lock_debug")]
            name: core::any::type_name::<T>(),
            #[cfg(feature = "lock_debug")]
            holder_pc: AtomicUsize::new(0),
            #[cfg(feature = "lock_debug")]
            holder_loc: AtomicUsize::new(0),
        }
    }

    #[cfg(feature = "lock_debug")]
    pub unsafe fn with_name(value: T, name: &'static str) -> Self {
        Self {
            inner: RefCell::new(value),
            name,
            holder_pc: AtomicUsize::new(0),
            holder_loc: AtomicUsize::new(0),
        }
    }

    #[cfg(not(feature = "lock_debug"))]
    pub unsafe fn with_name(value: T, _name: &'static str) -> Self {
        Self::new(value)
    }

    #[cfg(feature = "lock_debug")]
    #[track_caller]
    pub fn exclusive_access(&self) -> UPIntrRefMut<'_, T> {
        INTR_MASKING_INFO.get_mut().enter();
        let pc = caller_pc!();
        let loc = core::panic::Location::caller();
        match self.inner.try_borrow_mut() {
            Ok(guard) => {
                self.holder_pc.store(pc, Ordering::Release);
                self.holder_loc
                    .store(loc as *const _ as usize, Ordering::Release);
                UPIntrRefMut(Some(guard), Some(self))
            }
            Err(_) => {
                let holder = self.holder_pc.load(Ordering::Acquire);
                let holder_loc = self.holder_loc.load(Ordering::Acquire);
                let holder_loc = if holder_loc == 0 {
                    None
                } else {
                    Some(unsafe {
                        &*(holder_loc as *const core::panic::Location<'static>)
                    })
                };
                panic!(
                    "DEADLOCK: '{}' held at {}:{} (PC {:#x}), now trying at {}:{} (PC {:#x})",
                    self.name,
                    holder_loc.map(|l| l.file()).unwrap_or("<unknown>"),
                    holder_loc.map(|l| l.line()).unwrap_or(0),
                    holder,
                    loc.file(),
                    loc.line(),
                    pc
                );
            }
        }
    }

    #[cfg(not(feature = "lock_debug"))]
    pub fn exclusive_access(&self) -> UPIntrRefMut<'_, T> {
        INTR_MASKING_INFO.get_mut().enter();
        UPIntrRefMut(Some(self.inner.borrow_mut()))
    }

    #[track_caller]
    pub fn try_exclusive_access(&self) -> Option<UPIntrRefMut<'_, T>> {
        INTR_MASKING_INFO.get_mut().enter();
        match self.inner.try_borrow_mut() {
            Ok(guard) => {
                #[cfg(feature = "lock_debug")]
                {
                    self.holder_pc.store(caller_pc!(), Ordering::Release);
                    self.holder_loc.store(
                        core::panic::Location::caller() as *const _ as usize,
                        Ordering::Release,
                    );
                }
                #[cfg(feature = "lock_debug")]
                return Some(UPIntrRefMut(Some(guard), Some(self)));
                #[cfg(not(feature = "lock_debug"))]
                Some(UPIntrRefMut(Some(guard)))
            }
            Err(_) => {
                INTR_MASKING_INFO.get_mut().exit();
                None
            }
        }
    }

    pub fn exclusive_session<F, V>(&self, f: F) -> V
    where
        F: FnOnce(&mut T) -> V,
    {
        let mut inner = self.exclusive_access();
        f(inner.deref_mut())
    }
}

#[cfg(feature = "lock_debug")]
impl<T> Drop for UPIntrRefMut<'_, T> {
    fn drop(&mut self) {
        self.0 = None;
        if let Some(cell) = self.1 {
            cell.holder_pc.store(0, Ordering::Release);
            cell.holder_loc.store(0, Ordering::Release);
        }
        INTR_MASKING_INFO.get_mut().exit();
    }
}

#[cfg(not(feature = "lock_debug"))]
impl<T> Drop for UPIntrRefMut<'_, T> {
    fn drop(&mut self) {
        self.0 = None;
        INTR_MASKING_INFO.get_mut().exit();
    }
}

impl<T> Deref for UPIntrRefMut<'_, T> {
    type Target = T;
    fn deref(&self) -> &Self::Target {
        self.0.as_ref().unwrap().deref()
    }
}
impl<T> DerefMut for UPIntrRefMut<'_, T> {
    fn deref_mut(&mut self) -> &mut Self::Target {
        self.0.as_mut().unwrap().deref_mut()
    }
}

