/// `File` 是内核访问文件的统一虚拟接口。
///
/// 它封装了一个已打开的文件描述符，包含：
/// - `inner`: 底层具体文件，实现具体文件操作
/// - `flags`: 打开标志（不可变部分 + fcntl F_SETFL 可变部分）
/// - `dentry`: 关联的目录项（可选，用于普通文件/目录）
/// - `offset`: 文件读写偏移（可选，用于支持 seek 的对象）
///
/// 内核通过 `File` 接口访问所有类型的文件/设备，无需关心底层实现细节。
pub struct File {
    pub(crate) inner: Arc<Inode>,
    flags: OpenFlags,
    dentry: Option<Arc<Dentry>>,
    offset: Option<UPSafeCellRaw<usize>>,
    offset_lock: Option<MutexBlocking>,
}

impl File {
    /// 创建新的 File 实例。
    pub fn new(inode: Arc<Inode>, dentry: Option<Arc<Dentry>>, flags: OpenFlags) -> Self {
        Self {
            inner: inode,
            flags,
            dentry,
            offset: Some(unsafe { UPSafeCellRaw::new(0) }),
            offset_lock: Some(MutexBlocking::new()),
        }
    }

    /// 创建没有关联 dentry 的 File（如设备文件）。
    pub fn new_dev(inode: Arc<Inode>) -> Self {
        Self {
            inner: inode,
            flags: OpenFlags::O_RDWR,
            dentry: None,
            // 设备/pipe/socket 这类对象通常不支持 seek，因此不维护打开态 offset。
            offset: None,
            offset_lock: None,
        }
    }

    /// 创建无 dentry 的 File，flags 由调用方指定。
    pub fn new_dev_with_flags(inode: Arc<Inode>, flags: OpenFlags) -> Self {
        Self {
            inner: inode,
            flags,
            dentry: None,
            // 设备/pipe/socket 这类对象通常不支持 seek，因此不维护打开态 offset。
            offset: None,
            offset_lock: None,
        }
    }

    fn with_locked_offset<R>(&self, f: impl FnOnce(&mut usize) -> VfsRet<R>) -> VfsRet<R> {
        let lock = self.offset_lock.as_ref().ok_or(VfsError::IllegalSeek)?;
        let offset = self.offset.as_ref().ok_or(VfsError::IllegalSeek)?;
        lock.lock();
        let result = f(offset.get_mut());
        lock.unlock();
        result
    }

    fn read_from_position(&self, start: usize, buf: &mut [u8]) -> VfsRet<usize> {
        if !self.readable() {
            return Err(VfsError::PermissionDenied);
        }
        if self.inner.get_mode()?.is_dir() {
            return Err(VfsError::IsDirectory);
        }
        if self.offset.is_none() {
            return self.inner.read_at(0, buf);
        }

        let file_size = self.inner.get_size()?;
        let actual_end = (start + buf.len()).min(file_size);

        if start >= file_size {
            return Ok(0);
        }

        let mut total = 0usize;
        let mut pos = start;

        while pos < actual_end {
            let pgoff = (pos / PAGE_SIZE) as u64;
